import type { AppContext, FeatureModule } from "./contracts";

export interface AppEventHandlers {
  onInput?(event: Event, context: AppContext): boolean | void;
  onChange?(event: Event, context: AppContext): boolean | void;
  onClick?(event: MouseEvent, context: AppContext): boolean | void;
  onDblClick?(event: MouseEvent, context: AppContext): boolean | void;
  onContextMenu?(event: MouseEvent, context: AppContext): boolean | void;
  onPointerDown?(event: PointerEvent, context: AppContext): boolean | void;
  onFocusOut?(event: FocusEvent, context: AppContext): boolean | void;
  onWheel?(event: WheelEvent, context: AppContext): boolean | void;
  onWindowPointerMove?(event: PointerEvent, context: AppContext): boolean | void;
  onWindowPointerUp?(event: PointerEvent, context: AppContext): boolean | void;
  onWindowKeyDown?(event: KeyboardEvent, context: AppContext): boolean | void;
  onWindowKeyUp?(event: KeyboardEvent, context: AppContext): boolean | void;
}

export function bindAppEvents(
  context: AppContext,
  features: readonly FeatureModule[],
  hostHandlers: AppEventHandlers = {}
): () => void {
  const disposers: Array<() => void> = [];

  bindRoot("input", "onInput");
  bindRoot("change", "onChange");
  bindRoot("click", "onClick");
  bindRoot("dblclick", "onDblClick");
  bindRoot("contextmenu", "onContextMenu");
  bindRoot("pointerdown", "onPointerDown");
  bindRoot("focusout", "onFocusOut");
  bindRoot("wheel", "onWheel", { passive: false });
  bindWindow("pointermove", "onWindowPointerMove");
  bindWindow("pointerup", "onWindowPointerUp");
  bindWindow("keydown", "onWindowKeyDown");
  bindWindow("keyup", "onWindowKeyUp");

  return () => {
    for (const dispose of disposers.splice(0)) {
      dispose();
    }
  };

  function bindRoot<K extends keyof AppEventHandlers>(
    type: string,
    hook: K,
    options?: AddEventListenerOptions
  ): void {
    const listener = (event: Event): void => {
      if (dispatchFeatureEvent(hook, event)) return;
      const handler = hostHandlers[hook] as ((event: Event, context: AppContext) => boolean | void) | undefined;
      handler?.(event, context);
    };
    context.root.addEventListener(type, listener, options);
    disposers.push(() => context.root.removeEventListener(type, listener, options));
  }

  function bindWindow<K extends keyof AppEventHandlers>(
    type: string,
    hook: K,
    options?: AddEventListenerOptions
  ): void {
    const listener = (event: Event): void => {
      if (dispatchFeatureEvent(hook, event)) return;
      const handler = hostHandlers[hook] as ((event: Event, context: AppContext) => boolean | void) | undefined;
      handler?.(event, context);
    };
    window.addEventListener(type, listener, options);
    disposers.push(() => window.removeEventListener(type, listener, options));
  }

  function dispatchFeatureEvent<K extends keyof AppEventHandlers>(hook: K, event: Event): boolean {
    for (const feature of features) {
      const handler = feature[hook] as ((event: Event, context: AppContext) => boolean | void) | undefined;
      if (handler?.(event, context) === true) return true;
    }
    return false;
  }
}

import type { RenderScheduler } from "./contracts";

export const DEFAULT_RENDER_DEBOUNCE_MS = 40;

interface RenderTimerApi {
  setTimeout(handler: () => void, timeout: number): number;
  clearTimeout(handle: number): void;
}

const defaultTimerApi: RenderTimerApi = {
  setTimeout: (handler, timeout) => globalThis.setTimeout(handler, timeout) as unknown as number,
  clearTimeout: (handle) => globalThis.clearTimeout(handle)
};

export function createRenderScheduler(
  render: () => void,
  delayMs = DEFAULT_RENDER_DEBOUNCE_MS,
  timerApi: RenderTimerApi = defaultTimerApi
): RenderScheduler {
  let pendingTimer: number | null = null;
  let running = false;

  const cancel = (): void => {
    if (pendingTimer === null) return;
    timerApi.clearTimeout(pendingTimer);
    pendingTimer = null;
  };

  const flush = (): void => {
    if (running) {
      request();
      return;
    }
    cancel();
    running = true;
    try {
      render();
    } finally {
      running = false;
    }
  };

  const request = (): void => {
    cancel();
    pendingTimer = timerApi.setTimeout(() => {
      pendingTimer = null;
      flush();
    }, delayMs);
  };

  return {
    request,
    flush,
    cancel,
    isPending: () => pendingTimer !== null
  };
}

import type { AppRouteListener, AppRouter } from "./contracts";
import type { AppSectionId } from "../types";

const APP_SECTION_IDS: readonly AppSectionId[] = [
  "home",
  "income",
  "income_planning",
  "income_stamp_planner",
  "self_employment_dashboard",
  "planning_scenarios",
  "real_estate_financing",
  "statutory_pension",
  "combined_wealth"
];

const ROUTE_SECTION_ALIASES: Readonly<Record<string, AppSectionId>> = {
  income_tracking: "income",
  income_status: "income",
  income_charts: "income",
  income_overview: "income",
  cost_reserve_positions: "planning_scenarios",
  year_table: "planning_scenarios",
  investment_planning: "planning_scenarios",
  investment_overview: "planning_scenarios"
};

interface RouterWindow {
  location: Pick<Location, "hash" | "pathname" | "search">;
  history: Pick<History, "pushState" | "replaceState">;
  addEventListener(type: "popstate", listener: () => void): void;
  removeEventListener(type: "popstate", listener: () => void): void;
}

export function appSectionIdFromValue(value: unknown): AppSectionId | null {
  if (typeof value !== "string") return null;
  return ROUTE_SECTION_ALIASES[value] ?? (APP_SECTION_IDS.includes(value as AppSectionId) ? (value as AppSectionId) : null);
}

export function createAppRouter(routerWindow: RouterWindow = window): AppRouter {
  const listeners = new Set<AppRouteListener>();
  const notifyListeners = (): void => {
    const section = sectionFromLocationHash(routerWindow.location.hash);
    for (const listener of listeners) {
      listener(section);
    }
  };
  const popStateListener = (): void => notifyListeners();

  return {
    sectionFromValue: appSectionIdFromValue,
    currentSection: () => sectionFromLocationHash(routerWindow.location.hash),
    pushSection: (section) => pushSectionHistory(routerWindow, section),
    replaceSection: (section) => replaceSectionHistory(routerWindow, section),
    subscribe: (listener) => {
      if (!listeners.size) {
        routerWindow.addEventListener("popstate", popStateListener);
      }
      listeners.add(listener);
      return () => {
        listeners.delete(listener);
        if (!listeners.size) {
          routerWindow.removeEventListener("popstate", popStateListener);
        }
      };
    }
  };
}

export function sectionFromLocationHash(hash: string): AppSectionId | null {
  const normalizedHash = hash.replace(/^#/, "");
  if (!normalizedHash) return null;
  return appSectionIdFromValue(decodeURIComponent(normalizedHash));
}

function pushSectionHistory(routerWindow: RouterWindow, section: AppSectionId): void {
  const hash = `#${encodeURIComponent(section)}`;
  if (routerWindow.location.hash === hash) return;
  routerWindow.history.pushState({ activeSection: section }, "", sectionUrl(routerWindow, section));
}

function replaceSectionHistory(routerWindow: RouterWindow, section: AppSectionId): void {
  routerWindow.history.replaceState({ activeSection: section }, "", sectionUrl(routerWindow, section));
}

function sectionUrl(routerWindow: RouterWindow, section: AppSectionId): string {
  return `${routerWindow.location.pathname}${routerWindow.location.search}#${encodeURIComponent(section)}`;
}

