export function buildIncomeTrackerModel(tracker: IncomeTrackerState, options: IncomeTrackerModelOptions = {}): IncomeTrackerModel {
  const years = buildYearAnalyses(tracker);
  applyInflationValues(years, options.annualInflationRatePercent ?? null);

  const valueYears = years.filter((year) => year.annualNet !== null);
  const latest = last(valueYears);
  const previous = valueYears.length > 1 ? valueYears[valueYears.length - 2] : null;
  const first = valueYears[0] ?? null;
  const yearlyGrowthAmount = latest && previous ? latest.annualNet! - previous.annualNet! : null;
  const yearlyGrowthPercent =
    latest && previous && previous.annualNet !== null && previous.annualNet !== 0
      ? (yearlyGrowthAmount! / previous.annualNet) * 100
      : null;
  const averageGrowthRate =
    first && latest && first.year !== latest.year && first.annualNet !== null && latest.annualNet !== null && first.annualNet > 0
      ? Math.pow(latest.annualNet / first.annualNet, 1 / (latest.year - first.year)) - 1
      : null;
  const bestYear = valueYears.reduce<IncomeYearAnalysis | null>(
    (best, year) => (!best || year.annualNet! > best.annualNet! ? year : best),
    null
  );
  const weakestYear = valueYears.reduce<IncomeYearAnalysis | null>(
    (weakest, year) => (!weakest || year.annualNet! < weakest.annualNet! ? year : weakest),
    null
  );
  const extraMonthlySpace = yearlyGrowthAmount !== null ? yearlyGrowthAmount / 12 : null;
  const savingsSharePercent = tracker.settings.savingsSharePercent;
  const additionalSavingsRate =
    extraMonthlySpace !== null && savingsSharePercent !== null ? (extraMonthlySpace * savingsSharePercent) / 100 : null;
  const ratioYears = years.filter((year) => year.netRatio !== null);
  const averageNetRatio = ratioYears.length
    ? ratioYears.reduce((sum, year) => sum + year.netRatio!, 0) / ratioYears.length
    : null;
  const latestRatioYear = last(ratioYears);
  const previousRatioYear = ratioYears.length > 1 ? ratioYears[ratioYears.length - 2] : null;
  const netRatioChange =
    latestRatioYear && previousRatioYear ? latestRatioYear.netRatio! - previousRatioYear.netRatio! : null;
  const projection = buildProjection(tracker, valueYears, averageGrowthRate);

  const modelWithoutSummaries = {
    years,
    valueYears,
    latest,
    previous,
    first,
    yearlyGrowthAmount,
    yearlyGrowthPercent,
    averageGrowthRate,
    bestYear,
    weakestYear,
    extraMonthlySpace,
    savingsSharePercent,
    additionalSavingsRate,
    ratioYears,
    averageNetRatio,
    latestRatioYear,
    previousRatioYear,
    netRatioChange,
    projection,
    chartSummaries: []
  };

  return {
    ...modelWithoutSummaries,
    chartSummaries: buildChartSummaries(modelWithoutSummaries)
  };
}

export function buildIncomeChartModel(tracker: IncomeTrackerState, options: IncomeTrackerModelOptions = {}): IncomeTrackerModel {
  return buildIncomeTrackerModel(
    {
      ...tracker,
      yearlyEntries: tracker.yearlyEntries.filter((entry) => entry.visible)
    },
    options
  );
}

export function incomeYearEntryNetIncome(entry: IncomeYearEntry): number | null {
  const calculatedNet = incomeYearEntryCalculatedNetIncome(entry);
  return calculatedNet ?? (entry.annualNetIncome === null ? null : roundCents(entry.annualNetIncome));
}

export function incomeYearEntryCalculatedNetIncome(entry: IncomeYearEntry): number | null {
  const taxDeductions = incomeYearEntryTaxDeductions(entry);
  if (entry.annualGrossIncome === null || taxDeductions === null) return null;
  return roundCents(entry.annualGrossIncome - taxDeductions);
}

export function incomeYearEntryTaxDeductions(entry: IncomeYearEntry): number | null {
  const itemTotal = incomeTaxDeductionItemsTotal(entry.taxDeductionItems);
  const adjustment = incomeTaxAdjustmentSignedAmount(entry.taxAdjustment);
  if (itemTotal !== null) {
    const socialTotal = incomeTaxDeductionItemsSocialTotal(entry.taxDeductionItems) ?? 0;
    return roundCents(socialTotal + incomeYearEntryTaxTotal(entry));
  }
  if (entry.taxesAndDeductions === null && adjustment === 0) return null;
  return roundCents(Math.max(0, numberValue(entry.taxesAndDeductions) + adjustment));
}

export function incomeYearEntryTaxTotal(entry: IncomeYearEntry): number {
  const itemTotal = incomeTaxDeductionItemsTotal(entry.taxDeductionItems);
  const taxItemTotal = incomeTaxDeductionItemsTaxTotal(entry.taxDeductionItems);
  const baseTaxTotal = itemTotal === null ? numberValue(entry.taxesAndDeductions) : numberValue(taxItemTotal);
  return roundCents(Math.max(0, baseTaxTotal + incomeTaxAdjustmentSignedAmount(entry.taxAdjustment)));
}

export function incomeTaxAdjustmentSignedAmount(adjustment: IncomeTaxAdjustment | undefined): number {
  if (!adjustment) return 0;
  const amount = Math.max(0, numberValue(adjustment.amount));
  if (amount === 0) return 0;
  return adjustment.type === "payment" ? amount : -amount;
}

export function incomeTaxDeductionItemsTotal(items: IncomeTaxDeductionItems): number | null {
  return incomeTaxDeductionFieldTotal(items, TAX_DEDUCTION_FIELDS);
}

export function incomeTaxDeductionItemsTaxTotal(items: IncomeTaxDeductionItems): number | null {
  return incomeTaxDeductionFieldTotal(items, TAX_DEDUCTION_TAX_FIELDS);
}

export function incomeTaxDeductionItemsSocialTotal(items: IncomeTaxDeductionItems): number | null {
  return incomeTaxDeductionFieldTotal(items, TAX_DEDUCTION_SOCIAL_FIELDS);
}

export function capitalGainsTaxBreakdown(entry: IncomeYearEntry): CapitalGainsTaxBreakdown {
  const capitalIncome = Math.max(0, numberValue(entry.annualGrossIncome ?? entry.annualNetIncome));
  const allowance = Math.max(0, numberValue(entry.capitalGainsAllowance));
  const taxableAmount = roundCents(Math.max(0, capitalIncome - allowance));
  const churchRate = normalizedCapitalGainsChurchTaxRate(entry.capitalGainsChurchTaxRatePercent);
  const capitalGainsTax = entry.capitalGainsChurchTaxEnabled
    ? roundCents(taxableAmount / (4 + churchRate / 100))
    : roundCents((taxableAmount * CAPITAL_GAINS_TAX_PERCENT) / 100);
  const solidaritySurcharge = roundCents((capitalGainsTax * CAPITAL_GAINS_SOLIDARITY_SURCHARGE_PERCENT) / 100);
  const churchTax = entry.capitalGainsChurchTaxEnabled ? roundCents((capitalGainsTax * churchRate) / 100) : 0;
  return {
    capitalIncome,
    allowance,
    taxableAmount,
    capitalGainsTax,
    solidaritySurcharge,
    churchTax,
    totalTax: roundCents(capitalGainsTax + solidaritySurcharge + churchTax)
  };
}

export function applyCapitalGainsTaxToEntry(entry: IncomeYearEntry): IncomeYearEntry {
  if (!isCapitalGainsTaxRuleLabel(entry.label)) return clearCapitalGainsTaxItems(entry);
  const breakdown = capitalGainsTaxBreakdown(entry);
  const taxDeductionItems = {
    ...entry.taxDeductionItems,
    wageTax: null,
    solidaritySurcharge: null,
    churchTax: null,
    pensionInsurance: null,
    healthInsurance: null,
    careInsurance: null,
    unemploymentInsurance: null,
    employerPensionInsurance: null,
    capitalGainsTax: breakdown.capitalGainsTax,
    capitalGainsSolidaritySurcharge: breakdown.solidaritySurcharge,
    capitalGainsChurchTax: breakdown.churchTax
  };
  return {
    ...entry,
    capitalGainsChurchTaxRatePercent: normalizedCapitalGainsChurchTaxRate(entry.capitalGainsChurchTaxRatePercent),
    taxDeductionItems,
    taxAdjustment: emptyIncomeTaxAdjustment(),
    taxesAndDeductions: incomeTaxDeductionItemsTotal(taxDeductionItems)
  };
}

export function applyCapitalGainsTaxToEntries(entries: IncomeYearEntry[]): IncomeYearEntry[] {
  const allowanceUsedByYear = new Map<number, number>();
  return entries.map((entry) => {
    if (!isCapitalGainsTaxRuleLabel(entry.label)) {
      return applyCapitalGainsTaxToEntry({
        ...entry,
        capitalGainsAllowance: null,
        capitalGainsChurchTaxEnabled: false,
        capitalGainsChurchTaxRatePercent: DEFAULT_CAPITAL_GAINS_CHURCH_TAX_RATE_PERCENT
      });
    }

    const used = allowanceUsedByYear.get(entry.year) ?? 0;
    const maxAllowance = entry.active ? Math.max(0, CAPITAL_GAINS_ALLOWANCE_LIMIT - used) : CAPITAL_GAINS_ALLOWANCE_LIMIT;
    const sanitizedEntry = applyCapitalGainsTaxToEntry({
      ...entry,
      capitalGainsAllowance: capitalGainsAllowanceValue(entry.capitalGainsAllowance, maxAllowance),
      capitalGainsChurchTaxEnabled: Boolean(entry.capitalGainsChurchTaxEnabled),
      capitalGainsChurchTaxRatePercent: normalizedCapitalGainsChurchTaxRate(entry.capitalGainsChurchTaxRatePercent)
    });
    if (sanitizedEntry.active) {
      allowanceUsedByYear.set(
        sanitizedEntry.year,
        clampCurrency((allowanceUsedByYear.get(sanitizedEntry.year) ?? 0) + numberValue(sanitizedEntry.capitalGainsAllowance))
      );
    }
    return sanitizedEntry;
  });
}

export function emptyIncomeTaxAdjustment(): IncomeTaxAdjustment {
  return {
    type: "refund",
    amount: null
  };
}

function incomeTaxDeductionFieldTotal(items: IncomeTaxDeductionItems, fields: IncomeTaxDeductionField[]): number | null {
  const values = fields.map((field) => items[field]);
  if (!values.some((value) => value !== null && value !== undefined)) return null;
  return roundCents(values.reduce<number>((sum, value) => sum + numberValue(value), 0));
}

export function emptyIncomeTaxDeductionItems(): IncomeTaxDeductionItems {
  return {
    wageTax: null,
    solidaritySurcharge: null,
    churchTax: null,
    capitalGainsTax: null,
    capitalGainsSolidaritySurcharge: null,
    capitalGainsChurchTax: null,
    pensionInsurance: null,
    healthInsurance: null,
    careInsurance: null,
    unemploymentInsurance: null,
    employerPensionInsurance: null
  };
}

function clearCapitalGainsTaxItems(entry: IncomeYearEntry): IncomeYearEntry {
  if (
    entry.taxDeductionItems.capitalGainsTax === null &&
    entry.taxDeductionItems.capitalGainsSolidaritySurcharge === null &&
    entry.taxDeductionItems.capitalGainsChurchTax === null
  ) {
    return entry;
  }
  const taxDeductionItems = {
    ...entry.taxDeductionItems,
    capitalGainsTax: null,
    capitalGainsSolidaritySurcharge: null,
    capitalGainsChurchTax: null
  };
  return {
    ...entry,
    taxDeductionItems,
    taxesAndDeductions: incomeTaxDeductionItemsTotal(taxDeductionItems)
  };
}

function capitalGainsAllowanceValue(value: number | null | undefined, maxAllowance: number): number | null {
  const allowance = Math.min(Math.max(0, roundCents(numberValue(value ?? null))), Math.max(0, maxAllowance));
  return allowance > 0 ? allowance : null;
}

function clampCurrency(value: number): number {
  return Math.min(Math.max(0, roundCents(value)), CAPITAL_GAINS_ALLOWANCE_LIMIT);
}

function normalizedCapitalGainsChurchTaxRate(value: number | null | undefined): number {
  return value === 8 ? 8 : DEFAULT_CAPITAL_GAINS_CHURCH_TAX_RATE_PERCENT;
}

function buildYearAnalyses(tracker: IncomeTrackerState): IncomeYearAnalysis[] {
  const yearMap = new Map<number, IncomeYearAnalysis>();
  const getYear = (yearNumber: number): IncomeYearAnalysis => {
    const existing = yearMap.get(yearNumber);
    if (existing) return existing;
    const year: IncomeYearAnalysis = {
      year: yearNumber,
      annualStatementNet: null,
      manualNet: null,
      annualNet: null,
      source: null,
      ratioNet: 0,
      ratioGross: 0,
      netRatio: null,
      realNet: null,
      milestones: []
    };
    yearMap.set(yearNumber, year);
    return year;
  };

  for (const entry of tracker.yearlyEntries) {
    if (!entry.active) continue;
    const netIncome = incomeYearEntryNetIncome(entry);
    if (!validYear(entry.year) || netIncome === null) continue;
    const year = getYear(entry.year);
    if (entry.source === "annual_statement") {
      year.annualStatementNet = (year.annualStatementNet ?? 0) + netIncome;
    } else {
      year.manualNet = (year.manualNet ?? 0) + netIncome;
    }
    addNetRatioBasis(year, entry, netIncome);
  }

  for (const milestone of tracker.milestones) {
    const year = milestone.linkedYear ?? yearFromDate(milestone.date);
    if (!validYear(year)) continue;
    getYear(year).milestones.push(milestone);
  }

  const years = Array.from(yearMap.values()).sort((firstYear, secondYear) => firstYear.year - secondYear.year);
  for (const year of years) {
    if (year.annualStatementNet !== null) {
      year.annualNet = year.annualStatementNet;
      year.source = "annual_statement";
    } else if (year.manualNet !== null) {
      year.annualNet = year.manualNet;
      year.source = "manual";
    }

    if (year.ratioGross > 0) {
      year.netRatio = (year.ratioNet / year.ratioGross) * 100;
    }
  }

  return years;
}

function addNetRatioBasis(year: IncomeYearAnalysis, entry: IncomeYearEntry, netIncome: number): void {
  if (entry.annualGrossIncome === null || entry.annualGrossIncome <= 0) return;
  year.ratioNet += netIncome;
  year.ratioGross += entry.annualGrossIncome;
}

function applyInflationValues(years: IncomeYearAnalysis[], annualInflationRatePercent: number | null): void {
  if (annualInflationRatePercent === null || !Number.isFinite(annualInflationRatePercent) || annualInflationRatePercent <= -100) return;
  const baseYear = years.find((year) => year.annualNet !== null)?.year ?? null;
  if (baseYear === null) return;
  const annualRate = annualInflationRatePercent / 100;
  for (const year of years) {
    if (year.annualNet === null) continue;
    const factor = Math.pow(1 + annualRate, year.year - baseYear);
    if (Number.isFinite(factor) && factor !== 0) {
      year.realNet = year.annualNet / factor;
    }
  }
}

function buildProjection(
  tracker: IncomeTrackerState,
  valueYears: IncomeYearAnalysis[],
  averageGrowthRate: number | null
): IncomeProjectionModel {
  const latest = last(valueYears);
  if (tracker.settings.projectionMode === "off" || !latest || latest.annualNet === null) {
    return { enabled: false, rate: null, modeLabel: "", points: [], horizons: [] };
  }

  let rate: number | null = null;
  let modeLabel = "";
  if (tracker.settings.projectionMode === "manual" && tracker.settings.manualGrowthRatePercent !== null) {
    rate = tracker.settings.manualGrowthRatePercent / 100;
    modeLabel = "manuelle Wachstumsrate";
  }
  if (tracker.settings.projectionMode === "historical_average" && averageGrowthRate !== null) {
    rate = averageGrowthRate;
    modeLabel = "historische Wachstumsrate";
  }
  if (rate === null) {
    return { enabled: true, rate: null, modeLabel, points: [], horizons: [] };
  }

  const growthFactor = 1 + rate;
  if (!Number.isFinite(growthFactor) || growthFactor <= 0) {
    return { enabled: true, rate: null, modeLabel, points: [], horizons: [] };
  }

  const latestAnnualNet = latest.annualNet;
  const actualNetByYear = new Map(
    valueYears
      .filter((year): year is IncomeYearAnalysis & { annualNet: number } => year.annualNet !== null)
      .map((year) => [year.year, year.annualNet])
  );
  const projectionValue = (offset: number): number => {
    const year = latest.year + offset;
    if (offset <= 0) {
      const actualNet = actualNetByYear.get(year);
      if (actualNet !== undefined) return roundCents(actualNet);
    }
    return roundCents(latestAnnualNet * Math.pow(growthFactor, offset));
  };
  const points = PROJECTION_CHART_OFFSETS.map((offset) => ({
    year: latest.year + offset,
    value: projectionValue(offset),
    projected: offset > 0
  }));
  const horizons = PROJECTION_HORIZONS.map((years) => ({
    years,
    year: latest.year + years,
    value: roundCents(latestAnnualNet * Math.pow(growthFactor, years))
  }));
  return { enabled: true, rate, modeLabel, points, horizons };
}

function buildChartSummaries(model: Omit<IncomeTrackerModel, "chartSummaries">): IncomeChartSummary[] {
  return [
    {
      title: "Jahresnettoeinkommen",
      text: model.valueYears.length
        ? `${model.valueYears.length} Jahr(e), aktuell ${model.latest?.year} mit ${roundMoney(model.latest?.annualNet)}.`
        : "Keine Jahreswerte vorhanden."
    },
    {
      title: "Jaehrlicher Zuwachs",
      text:
        model.yearlyGrowthAmount !== null && model.previous
          ? `Letzte Veraenderung: ${roundMoney(model.yearlyGrowthAmount)} gegenueber ${model.previous.year}.`
          : "Mindestens zwei Jahreswerte noetig."
    },
    {
      title: "Inflationsbereinigung",
      text: model.valueYears.some((year) => year.realNet !== null)
        ? "Nominale und reale Werte nutzen die allgemeine Jahresinflation des Kontos."
        : "Keine realen Werte verfuegbar."
    },
    {
      title: "Nettoquote",
      text: model.ratioYears.length
        ? `${model.ratioYears.length} Jahr(e), Durchschnitt ${roundPercent(model.averageNetRatio)}.`
        : "Keine Jahre mit Brutto-/Netto-Daten."
    },
    {
      title: "Zukunftsprojektion",
      text:
        model.projection.horizons.length && model.projection.rate !== null
          ? `Aktiv mit ${roundPercent(model.projection.rate * 100)} Wachstumsannahme.`
          : "Keine aktive oder berechenbare Projektion."
    }
  ];
}

function numberValue(value: number | null): number {
  return typeof value === "number" && Number.isFinite(value) ? value : 0;
}

function roundCents(value: number): number {
  const rounded = Math.round((value + Number.EPSILON) * 100) / 100;
  return Object.is(rounded, -0) ? 0 : rounded;
}

function validYear(value: number | null): value is number {
  return typeof value === "number" && Number.isInteger(value) && value >= 1900 && value <= 2200;
}

function yearFromDate(value: string): number | null {
  const match = value.match(/^(\d{4})/);
  return match ? Number(match[1]) : null;
}

function last<T>(items: T[]): T | null {
  return items.length ? items[items.length - 1] : null;
}

function roundMoney(value: number | null | undefined): string {
  if (typeof value !== "number" || !Number.isFinite(value)) return "-";
  return `${Math.round(value).toLocaleString("de-DE")} EUR`;
}

function roundPercent(value: number | null | undefined): string {
  if (typeof value !== "number" || !Number.isFinite(value)) return "-";
  return `${value.toLocaleString("de-DE", { minimumFractionDigits: 1, maximumFractionDigits: 1 })} %`;
}

import {
  selectedInvestmentContributionForProjectionMonth,
  selectedInvestmentStartYear,
  selectedMonthlyPattern
} from "./investmentContributions";
import { RETIREMENT_DEPOT_MIN_AGE, retirementDepotAllowanceForProjectionMonth } from "./retirementDepot";
import type { InvestmentResult, InvestmentSettings, ReservePosition } from "../types";

export function annuityPayment(presentValue: number, monthlyRate: number, monthsCount: number): number {
  if (monthsCount <= 0) return 0;
  if (monthlyRate <= 0) return presentValue / monthsCount;
  return (presentValue * monthlyRate) / (1 - (1 + monthlyRate) ** -monthsCount);
}

export function calculateInvestmentResult(
  year: number,
  positions: ReservePosition[],
  settings: InvestmentSettings
): InvestmentResult {
  const ageToday = Math.max(0, year - settings.birthYear);
  const simulationStartYear = Math.max(
    settings.birthYear,
    Math.min(year, selectedInvestmentStartYear(positions, settings, year))
  );
  const simulationStartAge = Math.max(0, simulationStartYear - settings.birthYear);
  const payoutYears = Math.min(settings.payoutYears, settings.payoutEndAge);
  const rawPayoutStartAge = Math.max(0, settings.payoutEndAge - payoutYears);
  const payoutStartAge = settings.retirementDepotEnabled
    ? Math.max(RETIREMENT_DEPOT_MIN_AGE, rawPayoutStartAge)
    : rawPayoutStartAge;
  const effectivePayoutYears = Math.max(1, settings.payoutEndAge - payoutStartAge);
  const yearsUntilPayout = Math.max(0, payoutStartAge - ageToday);
  const savingMonths = Math.max(0, Math.round((payoutStartAge - simulationStartAge) * 12));
  const payoutMonths = Math.max(1, Math.round(effectivePayoutYears * 12));

  const monthlyPattern = selectedMonthlyPattern(positions, settings, year);
  const averageMonthlyContribution = monthlyPattern.reduce((sum, value) => sum + value, 0) / 12;
  const annualReturn = settings.investmentReturnPercent / 100;
  const monthlyReturn = (1 + annualReturn) ** (1 / 12) - 1;
  let grossWealth = 0;
  let totalContribution = 0;
  let totalAllowance = 0;

  for (let index = 0; index < savingMonths; index += 1) {
    const contribution = selectedInvestmentContributionForProjectionMonth(
      positions,
      settings,
      simulationStartYear,
      index
    );
    const allowance = retirementDepotAllowanceForProjectionMonth(positions, settings, simulationStartYear, index);
    grossWealth = grossWealth * (1 + monthlyReturn) + contribution + allowance;
    totalContribution += contribution;
    totalAllowance += allowance;
  }

  const growth = Math.max(0, grossWealth - totalContribution - totalAllowance);
  const taxBase = settings.retirementDepotEnabled ? grossWealth : growth;
  const tax = taxBase * investmentTaxRate(settings);
  const netWealth = Math.max(0, grossWealth - tax);
  const inflationFactor = (1 + settings.inflationRatePercent / 100) ** yearsUntilPayout;
  const realWealth = inflationFactor > 0 ? netWealth / inflationFactor : netWealth;
  const monthlyPensionNet = annuityPayment(netWealth, monthlyReturn, payoutMonths);
  const realMonthlyPension = inflationFactor > 0 ? monthlyPensionNet / inflationFactor : monthlyPensionNet;

  return {
    ageToday,
    payoutStartAge,
    yearsUntilPayout,
    savingMonths,
    payoutMonths,
    averageMonthlyContribution,
    totalContribution,
    grossWealth,
    growth,
    tax,
    netWealth,
    inflationFactor,
    realWealth,
    monthlyPensionNet,
    realMonthlyPension
  };
}

function investmentTaxRate(settings: InvestmentSettings): number {
  if (settings.retirementDepotEnabled) {
    return Math.min(45, Math.max(20, settings.retirementIncomeTaxRatePercent)) / 100;
  }

  return settings.capitalGainsTaxPercent / 100;
}

import { positionFlow } from "../lib/positionKinds";
import type { InvestmentSettings, ReservePosition } from "../types";

export function investmentContributionForMonth(position: ReservePosition, year: number, month: number): number {
  if (position.payoutType === "once") return 0;
  if (!isInvestmentSavingsActiveInMonth(position, year, month)) return 0;
  if (position.payoutType === "yearly") {
    return Number(position.payoutMonth) === month ? Number(position.amount) : 0;
  }
  return Number(position.amount);
}

export function oneTimeInvestmentContributionForMonth(
  position: ReservePosition,
  year: number,
  month: number
): number {
  if (position.payoutType === "once") {
    return isOneTimeInvestmentPayoutInMonth(position, year, month) ? Number(position.amount) : 0;
  }
  if (position.payoutType === "none") return investmentContributionForMonth(position, year, month);
  return 0;
}

export function selectedMonthlyPattern(
  positions: ReservePosition[],
  settings: InvestmentSettings,
  year: number
): number[] {
  const selectedPositions = positions.filter(
    (position) =>
      position.type === "savings" &&
      positionFlow(position) === "expense" &&
      settings.includedIds.includes(position.id) &&
      position.active
  );
  const pattern: number[] = [];

  for (let month = 1; month <= 12; month += 1) {
    pattern.push(
      selectedPositions.reduce((sum, position) => {
        return sum + investmentContributionForMonth(position, year, month);
      }, 0)
    );
  }

  return pattern;
}

export function selectedInvestmentContributionForProjectionMonth(
  positions: ReservePosition[],
  settings: InvestmentSettings,
  baseYear: number,
  projectionMonthIndex: number
): number {
  const calendarYear = baseYear + Math.floor(projectionMonthIndex / 12);
  const month = (projectionMonthIndex % 12) + 1;
  return selectedInvestmentPositions(positions, settings).reduce((sum, position) => {
    if (position.payoutType === "once") {
      return sum + oneTimeInvestmentContributionForMonth(position, calendarYear, month);
    }
    return sum + investmentContributionForMonth(position, calendarYear, month);
  }, 0);
}

export function selectedInvestmentContributionForProjectionYear(
  positions: ReservePosition[],
  settings: InvestmentSettings,
  baseYear: number,
  projectionYearIndex: number
): number {
  const firstMonthIndex = projectionYearIndex * 12;
  let total = 0;
  for (let offset = 0; offset < 12; offset += 1) {
    total += selectedInvestmentContributionForProjectionMonth(positions, settings, baseYear, firstMonthIndex + offset);
  }
  return total;
}

export function selectedSavingsContributionForProjectionYear(
  positions: ReservePosition[],
  selectedIds: string[],
  baseYear: number,
  projectionYearIndex: number
): number {
  const selected = new Set(selectedIds);
  const calendarYear = baseYear + projectionYearIndex;
  let total = 0;
  for (let month = 1; month <= 12; month += 1) {
    total += positions.reduce((sum, position) => {
      if (
        !position.active ||
        position.type !== "savings" ||
        positionFlow(position) !== "expense" ||
        !selected.has(position.id)
      ) {
        return sum;
      }
      if (position.payoutType === "once") {
        return sum + oneTimeInvestmentContributionForMonth(position, calendarYear, month);
      }
      return sum + investmentContributionForMonth(position, calendarYear, month);
    }, 0);
  }
  return total;
}

export function investmentSavingsSelectionSummary(
  positions: ReservePosition[],
  selectedIds: string[],
  baseYear: number
): { selectedCount: number; yearlyAmount: number } {
  const selected = new Set(selectedIds);
  const savingsPositions = selectableInvestmentSavingsPositions(positions);
  return {
    selectedCount: savingsPositions.filter((position) => selected.has(position.id)).length,
    yearlyAmount: selectedSavingsContributionForProjectionYear(savingsPositions, selectedIds, baseYear, 0)
  };
}

export function selectedRecurringInvestmentContributionForProjectionYear(
  positions: ReservePosition[],
  settings: InvestmentSettings,
  baseYear: number,
  projectionYearIndex: number
): number {
  const calendarYear = baseYear + projectionYearIndex;
  let total = 0;
  for (let month = 1; month <= 12; month += 1) {
    total += selectedInvestmentPositions(positions, settings).reduce((sum, position) => {
      if (position.payoutType === "once" || position.payoutType === "none") return sum;
      return sum + investmentContributionForMonth(position, calendarYear, month);
    }, 0);
  }
  return total;
}

export function selectedOneTimeInvestmentContributionForProjectionMonth(
  positions: ReservePosition[],
  settings: InvestmentSettings,
  baseYear: number,
  projectionMonthIndex: number
): number {
  const calendarYear = baseYear + Math.floor(projectionMonthIndex / 12);
  const month = (projectionMonthIndex % 12) + 1;
  return selectedInvestmentPositions(positions, settings).reduce((sum, position) => {
    return sum + oneTimeInvestmentContributionForMonth(position, calendarYear, month);
  }, 0);
}

export function selectedInvestmentStartYear(
  positions: ReservePosition[],
  settings: InvestmentSettings,
  fallbackYear: number
): number {
  return selectedInvestmentPositions(positions, settings).reduce((earliestYear, position) => {
    const startYear = investmentPositionYear(position, fallbackYear);
    return Number.isFinite(startYear) ? Math.min(earliestYear, startYear) : earliestYear;
  }, fallbackYear);
}

export function selectableInvestmentSavingsPositions(positions: ReservePosition[]): ReservePosition[] {
  return positions.filter(
    (position) => position.active && position.type === "savings" && positionFlow(position) === "expense"
  );
}

function selectedInvestmentPositions(positions: ReservePosition[], settings: InvestmentSettings): ReservePosition[] {
  return selectableInvestmentSavingsPositions(positions).filter((position) => settings.includedIds.includes(position.id));
}

function isInvestmentSavingsActiveInMonth(position: ReservePosition, year: number, monthNumber: number): boolean {
  if (!position.active || position.type !== "savings") return false;
  const startYear = investmentPositionYear(position, year);
  if (position.payoutType === "none") {
    return (
      year === startYear &&
      monthNumber >= Number(position.startMonth || 1) &&
      monthNumber <= Number(position.endMonth || 12)
    );
  }
  if (year < startYear) return false;
  return year > startYear || monthNumber >= Number(position.startMonth || 1);
}

function isOneTimeInvestmentPayoutInMonth(position: ReservePosition, year: number, monthNumber: number): boolean {
  return (
    position.active &&
    position.payoutType === "once" &&
    investmentPositionYear(position, year) === year &&
    Number(position.payoutMonth) === monthNumber
  );
}

function investmentPositionYear(position: ReservePosition, fallbackYear: number): number {
  const planningYear = Number(position.planningYear);
  if (position.planningYear !== null && position.planningYear !== undefined && Number.isFinite(planningYear)) {
    return planningYear;
  }
  const payoutYear = Number(position.payoutYear || fallbackYear);
  return Number.isFinite(payoutYear) ? payoutYear : fallbackYear;
}

import type {
  AdditionalRepaymentYearBreakdown,
  RealEstateFinancingMonth,
  RealEstateFinancingResult,
  RealEstateFinancingSettings,
  RealEstateFinancingSourceSchedule,
  RealEstateFinancingYear,
} from "../types";

const MAX_FINANCING_YEARS = 80;

export interface RealEstateFinancingCalculationOptions {
  financingYears?: number;
  projectionYears?: number;
  maxProjectionYears?: number;
}

export function validateRealEstateSettings(settings: RealEstateFinancingSettings): string[] {
  const errors: string[] = [];
  if (settings.purchasePrice <= 0) errors.push("Kaufpreis muss groesser als 0 sein.");
  if (settings.interestRatePercent < 0) errors.push("Zinssatz darf nicht negativ sein.");
  if (settings.propertyValueGrowthPercent < 0) errors.push("Immobilienwertsteigerung darf nicht negativ sein.");
  if (settings.financingStartAge < 0) errors.push("Finanzierung ab Alter darf nicht negativ sein.");
  return errors;
}

export function totalProjectCost(settings: RealEstateFinancingSettings): number {
  return roundMoney(
    settings.purchasePrice +
      settings.constructionOrRenovationCosts +
      settings.landCosts +
      settings.additionalPurchaseCosts +
      settings.notaryCosts +
      settings.landRegistryCosts +
      settings.brokerCosts +
      settings.transferTax +
      settings.modernizationReserve +
      settings.movingAndSetupCosts +
      settings.safetyBuffer
  );
}

export function deriveLoanAmount(settings: RealEstateFinancingSettings, equityCapital = 0): number {
  return roundMoney(Math.max(0, totalProjectCost(settings) - equityCapital));
}

export function deriveMonthlyPayment(settings: RealEstateFinancingSettings, loanAmount: number): number {
  if (settings.monthlyPayment > 0) return roundMoney(settings.monthlyPayment);
  const annualRatePercent = Math.max(0, settings.interestRatePercent + settings.initialRepaymentPercent);
  return roundMoney((loanAmount * annualRatePercent) / 100 / 12);
}

export function deriveRateLinkedMonthlyPayment(settings: RealEstateFinancingSettings): number {
  const loanAmount = deriveLoanAmount(settings);
  const annualRatePercent = Math.max(0, settings.interestRatePercent + settings.initialRepaymentPercent);
  return roundMoney((loanAmount * annualRatePercent) / 100 / 12);
}

export function deriveInitialRepaymentPercentFromMonthlyPayment(settings: RealEstateFinancingSettings): number {
  const loanAmount = deriveLoanAmount(settings);
  return deriveInitialRepaymentPercentFromPayment(settings, loanAmount, settings.monthlyPayment);
}

export function deriveInitialRepaymentPercentFromPayment(
  settings: RealEstateFinancingSettings,
  loanAmount: number,
  monthlyPayment: number
): number {
  if (loanAmount <= 0 || monthlyPayment <= 0) return 0;
  const totalAnnualRatePercent = (monthlyPayment * 12 / loanAmount) * 100;
  return roundMoney(Math.max(0, totalAnnualRatePercent - settings.interestRatePercent));
}

export function linkRealEstateFinancingInput(
  settings: RealEstateFinancingSettings,
  changedField: keyof RealEstateFinancingSettings
): RealEstateFinancingSettings {
  void changedField;
  return settings;
}

export function calculateRealEstateFinancing(
  startYear: number,
  settings: RealEstateFinancingSettings,
  sourceSchedule: RealEstateFinancingSourceSchedule = emptySourceSchedule(),
  options: RealEstateFinancingCalculationOptions = {}
): RealEstateFinancingResult {
  const validationErrors = validateRealEstateSettings(settings);
  const projectCost = totalProjectCost(settings);
  const equityCapital = roundMoney(Math.max(0, sourceSchedule.equityCapital));
  const loanAmount = deriveLoanAmount(settings, equityCapital);
  const fallbackProjectionYears = clampYears(options.financingYears ?? deriveFinancingYearsFromSettings(settings));
  const projectionYears = clampYears(options.projectionYears ?? fallbackProjectionYears);
  const maxProjectionYears = Math.max(projectionYears, clampYears(options.maxProjectionYears ?? projectionYears));
  const monthlyRate = Math.max(0, settings.interestRatePercent) / 100 / 12;
  const growthRate = Math.max(0, settings.propertyValueGrowthPercent) / 100;
  const startPropertyValue = Math.max(0, settings.purchasePrice + settings.constructionOrRenovationCosts + settings.landCosts);
  const firstMonthlyPayment = sourceMonthlyPayment(sourceSchedule, 0);
  const firstYearSpecialRepayment = firstYearSourceTotal(sourceSchedule.specialRepayments);
  const derivedInitialRepaymentPercent = deriveInitialRepaymentPercentFromPayment(
    settings,
    loanAmount,
    firstMonthlyPayment
  );

  if (loanAmount > 0 && !hasAnyMonthlyPayment(sourceSchedule, maxProjectionYears * 12)) {
    validationErrors.push("Bitte mindestens eine Sparposition fuer die Monatsrate auswaehlen.");
  }

  const years: RealEstateFinancingYear[] = [];
  const months: RealEstateFinancingMonth[] = [];

  let remainingDebt = loanAmount;
  let firstPaymentMonthIndex: number | null = null;
  let lastPaymentMonthIndex: number | null = null;

  for (let yearIndex = 0; yearIndex < maxProjectionYears; yearIndex += 1) {
    const year = startYear + yearIndex;
    const loanStart = roundMoney(remainingDebt);
    let interestPaidYear = 0;
    let interestDueYear = 0;
    let interestShortfallYear = 0;
    let monthlyPaymentFromSavingsYear = 0;
    let monthlyPaymentFromWithdrawalGainYear = 0;
    let monthlyPaymentAvailableYear = 0;
    let principalFromMonthlyPaymentYear = 0;
    let principalPaidYear = 0;
    let specialRepaymentYear = 0;
    let withdrawalGainPaymentUsedYear = 0;
    let depotSavingsRatePaymentUsedYear = 0;

    for (let month = 1; month <= 12; month += 1) {
      const scheduleIndex = yearIndex * 12 + month - 1;
      const monthLoanStart = roundMoney(remainingDebt);

      if (remainingDebt <= 0) {
        months.push({
          year,
          month,
          loanStart: monthLoanStart,
          interestDue: 0,
          interestPaid: 0,
          interestShortfall: 0,
          monthlyPaymentFromSavings: 0,
          monthlyPaymentFromWithdrawalGain: 0,
          monthlyPaymentAvailable: 0,
          principalPaid: 0,
          specialRepayment: 0,
          additionalRepayment: 0,
          loanEnd: 0
        });
        remainingDebt = 0;
        continue;
      }

      const monthlyPaymentFromSavings = sourceValue(sourceSchedule.monthlyPaymentSavings, scheduleIndex);
      const monthlyPaymentFromWithdrawalGain = sourceValue(sourceSchedule.withdrawalGainPayments, scheduleIndex);
      const depotSavingsRatePayment = sourceValue(sourceSchedule.depotSavingsRatePayments, scheduleIndex);
      const monthlyPaymentAvailable = roundMoney(
        monthlyPaymentFromSavings + monthlyPaymentFromWithdrawalGain + depotSavingsRatePayment
      );
      const interestDue = roundMoney(remainingDebt * monthlyRate);
      const maximumUsefulPayment = roundMoney(interestDue + remainingDebt);
      const usedMonthlyPayment = roundMoney(Math.min(monthlyPaymentAvailable, maximumUsefulPayment));
      let interestPaid = roundMoney(Math.min(usedMonthlyPayment, interestDue));
      let interestShortfall = roundMoney(Math.max(0, interestDue - interestPaid));
      const principalBudget = interestShortfall > 0 ? 0 : roundMoney(usedMonthlyPayment - interestPaid);
      const principalPaid = roundMoney(Math.min(Math.max(0, principalBudget), remainingDebt));
      remainingDebt = roundMoney(remainingDebt - principalPaid);
      const withdrawalShare =
        monthlyPaymentAvailable > 0 ? roundMoney(usedMonthlyPayment * (monthlyPaymentFromWithdrawalGain / monthlyPaymentAvailable)) : 0;
      const depotSavingsRateShare =
        monthlyPaymentAvailable > 0 ? roundMoney(usedMonthlyPayment * (depotSavingsRatePayment / monthlyPaymentAvailable)) : 0;

      const specialPaymentAvailable = sourceValue(sourceSchedule.specialRepayments, scheduleIndex);
      const specialInterestPayment = roundMoney(Math.min(specialPaymentAvailable, interestShortfall));
      interestPaid = roundMoney(interestPaid + specialInterestPayment);
      interestShortfall = roundMoney(interestShortfall - specialInterestPayment);
      const specialPrincipalBudget = interestShortfall > 0 ? 0 : roundMoney(specialPaymentAvailable - specialInterestPayment);
      const specialRepayment = roundMoney(Math.min(specialPrincipalBudget, remainingDebt));
      remainingDebt = roundMoney(remainingDebt - specialRepayment);
      remainingDebt = roundMoney(remainingDebt + interestShortfall);
      const totalPaymentUsed = roundMoney(interestPaid + principalPaid + specialRepayment);
      if (totalPaymentUsed > 0) {
        firstPaymentMonthIndex ??= scheduleIndex;
        lastPaymentMonthIndex = scheduleIndex;
      }

      interestDueYear += interestDue;
      interestPaidYear += interestPaid;
      interestShortfallYear += interestShortfall;
      monthlyPaymentFromSavingsYear += monthlyPaymentFromSavings;
      monthlyPaymentFromWithdrawalGainYear += monthlyPaymentFromWithdrawalGain;
      monthlyPaymentAvailableYear += monthlyPaymentAvailable;
      principalFromMonthlyPaymentYear += principalPaid;
      principalPaidYear += principalPaid + specialRepayment;
      specialRepaymentYear += specialRepayment;
      withdrawalGainPaymentUsedYear += withdrawalShare;
      depotSavingsRatePaymentUsedYear += depotSavingsRateShare;

      months.push({
        year,
        month,
        loanStart: monthLoanStart,
        interestDue,
        interestPaid,
        interestShortfall,
        monthlyPaymentFromSavings,
        monthlyPaymentFromWithdrawalGain,
        monthlyPaymentAvailable,
        principalPaid,
        specialRepayment,
        additionalRepayment: roundMoney(withdrawalShare + depotSavingsRateShare),
        loanEnd: roundMoney(remainingDebt)
      });
    }

    const propertyValue = projectedPropertyValue(startPropertyValue, growthRate, yearIndex + 1);
    const loanEnd = roundMoney(remainingDebt);
    const propertyEquity = roundMoney(propertyValue - loanEnd);
    const netPropertyWealth = roundMoney(propertyValue - loanEnd);

    years.push({
      year,
      propertyValue,
      loanStart,
      interestPaid: roundMoney(interestPaidYear),
      interestDue: roundMoney(interestDueYear),
      interestShortfall: roundMoney(interestShortfallYear),
      monthlyPaymentFromSavings: roundMoney(monthlyPaymentFromSavingsYear),
      monthlyPaymentFromWithdrawalGain: roundMoney(monthlyPaymentFromWithdrawalGainYear),
      monthlyPaymentAvailable: roundMoney(monthlyPaymentAvailableYear),
      principalFromMonthlyPayment: roundMoney(principalFromMonthlyPaymentYear),
      principalPaid: roundMoney(principalPaidYear),
      specialRepayment: roundMoney(specialRepaymentYear),
      additionalRepayment: roundMoney(withdrawalGainPaymentUsedYear + depotSavingsRatePaymentUsedYear),
      additionalRepaymentBreakdown: additionalRepaymentYearBreakdown(
        withdrawalGainPaymentUsedYear,
        depotSavingsRatePaymentUsedYear
      ),
      loanEnd,
      propertyEquity,
      netPropertyWealth
    });

    if (remainingDebt <= 0 && yearIndex + 1 >= projectionYears) break;
  }

  const totalInterestDue = roundMoney(years.reduce((sum, entry) => sum + entry.interestDue, 0));
  const totalInterestPaid = roundMoney(years.reduce((sum, entry) => sum + entry.interestPaid, 0));
  const totalInterestShortfall = roundMoney(years.reduce((sum, entry) => sum + entry.interestShortfall, 0));
  const financingYears = actualFinancingYears(firstPaymentMonthIndex, lastPaymentMonthIndex, years.length);
  const totalLoanCost = roundMoney(loanAmount + totalInterestDue);
  applyLoanCostProgress(years, totalLoanCost);
  if (totalInterestShortfall > 0) {
    validationErrors.push(
      `Die ausgewaehlten Zahlungsquellen decken die Zinsen nicht vollstaendig (${totalInterestShortfall.toFixed(2)} EUR fehlen).`
    );
  }
  const finalDebt = years[years.length - 1]?.loanEnd ?? loanAmount;
  if (loanAmount > 0 && finalDebt > 0) {
    validationErrors.push(
      `Die Finanzierung ist innerhalb des Projektionszeitraums nicht vollstaendig getilgt (${finalDebt.toFixed(2)} EUR offen).`
    );
  }

  return {
    years,
    months,
    startLoanAmount: loanAmount,
    equityCapital,
    monthlyPayment: roundMoney(firstMonthlyPayment),
    derivedInitialRepaymentPercent,
    annualSpecialRepayment: roundMoney(firstYearSpecialRepayment),
    effectivePropertyStartValue: startPropertyValue,
    totalProjectCost: projectCost,
    totalInterestDue,
    totalInterestPaid,
    totalInterestShortfall,
    totalLoanCost,
    financingYears,
    projectionYears: years.length,
    financingEndYear: financingEndYear(startYear, lastPaymentMonthIndex, financingYears),
    projectionEndYear: years[years.length - 1]?.year ?? startYear,
    validationErrors
  };
}

export function defaultRealEstateDetailYear(
  years: RealEstateFinancingYear[],
  selectedYear: number | null
): number | null {
  if (selectedYear !== null && years.some((entry) => entry.year === selectedYear)) return selectedYear;
  const firstActiveCreditYear = years.find((entry) => entry.loanStart > 0 || entry.loanEnd > 0 || entry.interestDue > 0);
  return firstActiveCreditYear?.year ?? years[0]?.year ?? null;
}

function additionalRepaymentYearBreakdown(withdrawalGain: number, depotSavingsRate: number): AdditionalRepaymentYearBreakdown {
  return {
    withdrawalGain: roundMoney(withdrawalGain),
    depotSavingsRate: roundMoney(depotSavingsRate),
    legacySavingsRate: 0,
    netGain: 0,
    totalAdditionalRepayment: roundMoney(withdrawalGain + depotSavingsRate)
  };
}

function emptySourceSchedule(): RealEstateFinancingSourceSchedule {
  return {
    equityCapital: 0,
    monthlyPaymentSavings: [],
    withdrawalGainPayments: [],
    specialRepayments: []
  };
}

function sourceMonthlyPayment(schedule: RealEstateFinancingSourceSchedule, index: number): number {
  return roundMoney(
    sourceValue(schedule.monthlyPaymentSavings, index) +
      sourceValue(schedule.withdrawalGainPayments, index) +
      sourceValue(schedule.depotSavingsRatePayments, index)
  );
}

function sourceValue(values: number[] | undefined, index: number): number {
  const value = values?.[index] ?? 0;
  return Number.isFinite(value) ? roundMoney(Math.max(0, value)) : 0;
}

function firstYearSourceTotal(values: number[] | undefined): number {
  let total = 0;
  for (let index = 0; index < 12; index += 1) {
    total += sourceValue(values, index);
  }
  return roundMoney(total);
}

function hasAnyMonthlyPayment(schedule: RealEstateFinancingSourceSchedule, monthCount: number): boolean {
  for (let index = 0; index < monthCount; index += 1) {
    if (sourceMonthlyPayment(schedule, index) > 0) return true;
  }
  return false;
}

function projectedPropertyValue(startPropertyValue: number, growthRate: number, yearIndex: number): number {
  return roundMoney(startPropertyValue * (1 + growthRate) ** yearIndex);
}

function applyLoanCostProgress(years: RealEstateFinancingYear[], totalLoanCost: number): void {
  let paidToDate = 0;
  for (const year of years) {
    paidToDate = roundMoney(paidToDate + paidLoanCostForYear(year));
    const remainingByCost = roundMoney(Math.max(0, totalLoanCost - Math.min(totalLoanCost, paidToDate)));
    year.loanCostRemaining = year.loanEnd <= 0 ? 0 : roundMoney(Math.max(remainingByCost, year.loanEnd));
    year.loanCostPaidToDate = roundMoney(Math.max(0, totalLoanCost - year.loanCostRemaining));
  }
}

function paidLoanCostForYear(year: RealEstateFinancingYear): number {
  return roundMoney(Math.max(0, year.interestPaid) + Math.max(0, year.principalPaid));
}

function actualFinancingYears(
  firstPaymentMonthIndex: number | null,
  lastPaymentMonthIndex: number | null,
  fallbackYears: number
): number {
  if (firstPaymentMonthIndex === null || lastPaymentMonthIndex === null || lastPaymentMonthIndex < firstPaymentMonthIndex) {
    return fallbackYears;
  }
  return clampYears(Math.ceil((lastPaymentMonthIndex - firstPaymentMonthIndex + 1) / 12));
}

function financingEndYear(startYear: number, lastPaymentMonthIndex: number | null, financingYears: number): number {
  if (lastPaymentMonthIndex === null) return startYear + financingYears - 1;
  return startYear + Math.floor(lastPaymentMonthIndex / 12);
}

function deriveFinancingYearsFromSettings(settings: RealEstateFinancingSettings): number {
  return settings.financingYears || settings.targetTermYears || 1;
}

function clampYears(value: number): number {
  if (!Number.isFinite(value) || value <= 0) return 1;
  return Math.max(1, Math.min(MAX_FINANCING_YEARS, Math.round(value)));
}

function roundMoney(value: number): number {
  return Math.round((value + Number.EPSILON) * 100) / 100;
}

import { MONTHS } from "../data/defaults";
import { isExpensePosition, isIncomePosition } from "../lib/positionKinds";
import type { MonthlyReserveRow, PlanningSettings, ReservePosition, ReserveSummary } from "../types";

export function daysInMonth(year: number, monthIndex: number): number {
  return new Date(year, monthIndex + 1, 0).getDate();
}

export function isActiveInMonth(position: ReservePosition, monthNumber: number): boolean {
  return position.active && monthNumber >= Number(position.startMonth) && monthNumber <= Number(position.endMonth);
}

export function isSavingsActiveInMonth(position: ReservePosition, year: number, monthNumber: number): boolean {
  if (!position.active || position.type !== "savings") return false;
  const startYear = Number(position.payoutYear || year);
  if (position.payoutType === "none") {
    return (
      year === startYear &&
      monthNumber >= Number(position.startMonth || 1) &&
      monthNumber <= Number(position.endMonth || 12)
    );
  }
  if (year < startYear) return false;
  return year > startYear || monthNumber >= Number(position.startMonth || 1);
}

export function isOneTimePayoutInMonth(position: ReservePosition, year: number, monthNumber: number): boolean {
  return (
    position.active &&
    position.payoutType === "once" &&
    Number(position.payoutYear) === year &&
    Number(position.payoutMonth) === monthNumber
  );
}

function calculateYearlyReserveCycleBalance(position: ReservePosition, monthNumber: number): number {
  const payoutMonth = Number(position.payoutMonth);
  const cycleMonth = ((monthNumber - payoutMonth + 11) % 12) + 1;
  return Number(position.amount) * cycleMonth;
}

export function calculatePositionValueAtMonthStart(
  position: ReservePosition,
  year: number,
  monthNumber: number
): number {
  if (isIncomePosition(position)) return 0;
  if (position.type === "savings") {
    if (!isSavingsActiveInMonth(position, year, monthNumber)) return 0;
    return position.payoutType === "once" ? 0 : Number(position.amount);
  }
  if (!isActiveInMonth(position, monthNumber)) return 0;

  if (position.payoutType === "once") return 0;
  if (position.type === "fixed") return Number(position.amount);
  if (position.type === "temporary") return Number(position.amount);
  if (position.type === "reserve" && position.payoutType === "yearly") {
    return calculateYearlyReserveCycleBalance(position, monthNumber);
  }

  let balance = 0;
  for (let month = 1; month <= monthNumber; month += 1) {
    if (isActiveInMonth(position, month)) balance += Number(position.amount);
    if (position.payoutType === "monthly" && isActiveInMonth(position, month)) balance = 0;
    if (isSingleMonthPayout(position) && month < monthNumber && isPayoutMonth(position, month)) {
      balance = 0;
    }
  }

  return balance;
}

export function calculatePositionEndOfMonthPermanent(position: ReservePosition, monthNumber: number): number {
  if (isIncomePosition(position)) return 0;
  if (!position.active) return 0;
  if (position.payoutType === "once") return 0;

  if (position.type === "fixed") {
    return isActiveInMonth(position, monthNumber) ? Number(position.amount) : 0;
  }
  if (position.type === "temporary" || position.type === "savings") return 0;
  if (position.type === "reserve" && position.payoutType === "yearly" && isActiveInMonth(position, monthNumber)) {
    return isPayoutMonth(position, monthNumber) ? 0 : calculateYearlyReserveCycleBalance(position, monthNumber);
  }

  let balance = 0;
  for (let month = 1; month <= monthNumber; month += 1) {
    if (isActiveInMonth(position, month)) balance += Number(position.amount);
    if (position.payoutType === "monthly" && isActiveInMonth(position, month)) balance = 0;
    if (isSingleMonthPayout(position) && isPayoutMonth(position, month) && month <= monthNumber) {
      balance = 0;
    }
  }

  return balance;
}

export function calculateInterestForSingleMonth(
  position: ReservePosition,
  year: number,
  monthNumber: number,
  annualRate: number
): number {
  if (isIncomePosition(position)) return 0;
  if (!position.active || !position.interestBearing) return 0;
  if (position.type === "savings" && !isSavingsActiveInMonth(position, year, monthNumber)) return 0;
  if (position.type !== "savings" && !isActiveInMonth(position, monthNumber)) return 0;
  if (position.payoutType === "once") return 0;

  const monthIndex = monthNumber - 1;
  const dim = daysInMonth(year, monthIndex);

  if (position.type === "fixed") return (Number(position.amount) * annualRate) / 12;

  if (position.type === "temporary" || position.type === "savings") {
    const payoutDay = Math.max(1, Math.min(Number(position.payoutDay || dim), dim));
    return (Number(position.amount) * annualRate * payoutDay) / 365;
  }

  const balance = calculatePositionValueAtMonthStart(position, year, monthNumber);
  let daysHeld = dim;
  if (position.payoutType === "monthly") daysHeld = Math.max(1, Math.min(Number(position.payoutDay || dim), dim));
  if (isSingleMonthPayout(position) && isPayoutMonth(position, monthNumber)) {
    daysHeld = Math.max(1, Math.min(Number(position.payoutDay || dim), dim));
  }
  return (balance * annualRate * daysHeld) / 365;
}

export function calculateInterestForPosition(position: ReservePosition, year: number, annualRate: number): number {
  let interest = 0;
  for (let month = 1; month <= 12; month += 1) {
    interest += calculateInterestForSingleMonth(position, year, month, annualRate);
  }
  return interest;
}

export function calculateCashbackForPosition(position: ReservePosition, year: number, cashbackRate: number): number {
  let cashback = 0;
  for (let month = 1; month <= 12; month += 1) {
    cashback += calculateCashbackForSingleMonth(position, year, month, cashbackRate);
  }
  return cashback;
}

export function calculateCashbackForSingleMonth(
  position: ReservePosition,
  year: number,
  monthNumber: number,
  cashbackRate: number
): number {
  if (isIncomePosition(position)) return 0;
  if (!position.active || !position.cashback || position.type !== "temporary") return 0;
  if (position.payoutType === "once") {
    return isOneTimePayoutInMonth(position, year, monthNumber) ? Number(position.amount) * cashbackRate : 0;
  }
  if (!isActiveInMonth(position, monthNumber)) return 0;
  if (position.payoutType === "monthly") return Number(position.amount) * cashbackRate;
  if (position.payoutType === "yearly" && isPayoutMonth(position, monthNumber)) {
    return Number(position.amount) * cashbackRate;
  }

  return 0;
}

export function calculatePlannedOutflowForSingleMonth(
  position: ReservePosition,
  year: number,
  monthNumber: number
): number {
  if (!position.active || isIncomePosition(position) || position.type === "fixed") return 0;
  if (position.payoutType === "once") {
    return isOneTimePayoutInMonth(position, year, monthNumber) ? Number(position.amount) : 0;
  }
  if (position.type === "savings") {
    if (!isSavingsActiveInMonth(position, year, monthNumber)) return 0;
    return position.payoutType === "yearly" && !isPayoutMonth(position, monthNumber) ? 0 : Number(position.amount);
  }
  if (!isActiveInMonth(position, monthNumber)) return 0;
  if (position.type === "reserve") return Number(position.amount);
  if (position.payoutType === "yearly") return isPayoutMonth(position, monthNumber) ? Number(position.amount) : 0;
  return Number(position.amount);
}

export function calculatePlannedIncomeForSingleMonth(
  position: ReservePosition,
  year: number,
  monthNumber: number
): number {
  if (!position.active || !isIncomePosition(position)) return 0;
  if (position.payoutType === "once") {
    return isOneTimePayoutInMonth(position, year, monthNumber) ? Number(position.amount) : 0;
  }
  if (!isIncomeActiveInMonth(position, year, monthNumber)) return 0;
  if (position.payoutType === "yearly" || position.type === "incomeYearly") {
    return isPayoutMonth(position, monthNumber) ? Number(position.amount) : 0;
  }
  return Number(position.amount);
}

function isIncomeActiveInMonth(position: ReservePosition, year: number, monthNumber: number): boolean {
  if (!isActiveInMonth(position, monthNumber)) return false;
  const payoutYear = Number(position.payoutYear || year);
  if (position.type === "incomeTemporary" || position.payoutType === "none") return year === payoutYear;
  return year >= payoutYear;
}

function isSingleMonthPayout(position: ReservePosition): boolean {
  return position.payoutType === "yearly" || position.payoutType === "once";
}

function isPayoutMonth(position: ReservePosition, monthNumber: number): boolean {
  return Number(position.payoutMonth) === monthNumber;
}

function normalizedPositionName(name: string): string {
  return name
    .trim()
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\s+/g, " ")
    .toLowerCase();
}

function reserveCoversExpenseInMonth(position: ReservePosition, year: number, monthNumber: number): boolean {
  if (!position.active || position.type !== "reserve") return false;
  if (position.payoutType === "monthly") return isActiveInMonth(position, monthNumber);
  if (position.payoutType === "yearly") return isActiveInMonth(position, monthNumber) && isPayoutMonth(position, monthNumber);
  if (position.payoutType === "once") return isOneTimePayoutInMonth(position, year, monthNumber);
  return false;
}

function reserveFundedExpenseNamesForMonth(
  positions: ReservePosition[],
  year: number,
  monthNumber: number
): Set<string> {
  return new Set(
    positions
      .filter((position) => reserveCoversExpenseInMonth(position, year, monthNumber))
      .map((position) => normalizedPositionName(position.name))
      .filter(Boolean)
  );
}

function isReserveFundedExpense(position: ReservePosition, reserveFundedExpenseNames: Set<string>): boolean {
  return (
    isExpensePosition(position) &&
    position.type === "temporary" &&
    reserveFundedExpenseNames.has(normalizedPositionName(position.name))
  );
}

export function calculateMonthlyRows(settings: PlanningSettings, positions: ReservePosition[]): MonthlyReserveRow[] {
  const rows: MonthlyReserveRow[] = [];
  const annualRate = settings.interestRatePercent / 100;
  const cashbackRate = settings.cashbackRatePercent / 100;

  for (let month = 1; month <= 12; month += 1) {
    const reserveFundedExpenseNames = reserveFundedExpenseNamesForMonth(positions, settings.year, month);
    const values: Record<string, number> = {};
    let plannedIncome = 0;
    let maxNeeded = 0;
    let plannedOutflow = 0;
    let permanentAfterMonthlyOutflows = 0;
    let monthlyInterest = 0;
    let monthlyCashback = 0;

    for (const position of positions) {
      if (!position.active) {
        values[position.id] = 0;
        continue;
      }

      const income = calculatePlannedIncomeForSingleMonth(position, settings.year, month);
      const value = isIncomePosition(position)
        ? income
        : calculatePositionValueAtMonthStart(position, settings.year, month);
      values[position.id] = value;
      plannedIncome += income;
      if (isExpensePosition(position)) maxNeeded += value;
      const outflow = calculatePlannedOutflowForSingleMonth(position, settings.year, month);
      plannedOutflow += isReserveFundedExpense(position, reserveFundedExpenseNames) ? 0 : outflow;
      permanentAfterMonthlyOutflows += calculatePositionEndOfMonthPermanent(position, month);
      monthlyInterest += calculateInterestForSingleMonth(position, settings.year, month, annualRate);
      monthlyCashback += calculateCashbackForSingleMonth(position, settings.year, month, cashbackRate);
    }

    rows.push({
      monthNumber: month,
      month: MONTHS[month - 1],
      values,
      plannedIncome,
      maxNeeded,
      plannedOutflow,
      monthlyRemaining: plannedIncome - plannedOutflow,
      permanentAfterMonthlyOutflows,
      monthlyInterest,
      monthlyCashback
    });
  }

  return rows;
}

export function calculateYearTableFooterValue(position: ReservePosition, rows: MonthlyReserveRow[], year: number): number {
  if (isIncomePosition(position)) {
    return rows.reduce((sum, row) => sum + (row.values[position.id] || 0), 0);
  }
  if (position.type === "reserve") {
    return rows.reduce((sum, row) => sum + calculatePlannedOutflowForSingleMonth(position, year, row.monthNumber), 0);
  }
  return rows[11]?.values[position.id] || 0;
}

export function calculateReserveSummary(settings: PlanningSettings, positions: ReservePosition[]): ReserveSummary {
  const rows = calculateMonthlyRows(settings, positions);
  const activePositions = positions.filter((position) => position.active && position.payoutType !== "once");
  const visiblePositions = activePositions.filter((position) => position.visible);
  const maxRow = rows.reduce((best, row) => (row.maxNeeded > best.maxNeeded ? row : best), rows[0]);
  const minRemainingRow = rows.reduce(
    (lowest, row) => (row.monthlyRemaining < lowest.monthlyRemaining ? row : lowest),
    rows[0]
  );
  const annualRate = settings.interestRatePercent / 100;
  const totalInterest = positions.reduce(
    (sum, position) => sum + calculateInterestForPosition(position, settings.year, annualRate),
    0
  );
  const totalCashback = rows.reduce((sum, row) => sum + row.monthlyCashback, 0);
  const totalPlannedIncome = rows.reduce((sum, row) => sum + row.plannedIncome, 0);
  const totalPlannedOutflow = rows.reduce((sum, row) => sum + row.plannedOutflow, 0);
  const yearlyRemaining = totalPlannedIncome - totalPlannedOutflow;
  const yearEndBalance = rows[11]?.permanentAfterMonthlyOutflows || 0;

  return {
    rows,
    activePositions,
    visiblePositions,
    maxRow,
    minRemainingRow,
    totalPlannedIncome,
    totalPlannedOutflow,
    yearlyRemaining,
    totalInterest,
    totalCashback,
    yearEndBalance,
    maxNeededWithEmergencyFund: maxRow.maxNeeded + settings.emergencyFund
  };
}

import {
  selectedInvestmentContributionForProjectionMonth,
  selectedInvestmentContributionForProjectionYear
} from "./investmentContributions";
import type { InvestmentSettings, ReservePosition } from "../types";

export const RETIREMENT_DEPOT_MIN_AGE = 65;
const MINIMUM_ANNUAL_CONTRIBUTION_FOR_ALLOWANCE = 120;
const BASE_ALLOWANCE_FIRST_TIER_LIMIT = 360;
const BASE_ALLOWANCE_SECOND_TIER_LIMIT = 1800;
const BASE_ALLOWANCE_FIRST_TIER_RATE = 0.5;
const BASE_ALLOWANCE_SECOND_TIER_RATE = 0.25;
const CHILD_ALLOWANCE_LIMIT = 300;

export interface RetirementDepotAllowance {
  annualOwnContribution: number;
  baseAllowance: number;
  childAllowance: number;
  totalAllowance: number;
  allowanceRatePercent: number;
  annualContributionWithAllowance: number;
}

export function calculateRetirementDepotAllowance(
  annualOwnContribution: number,
  childrenCount: number
): RetirementDepotAllowance {
  const ownContribution = Math.max(0, Number(annualOwnContribution) || 0);
  const children = Math.max(0, Math.floor(Number(childrenCount) || 0));
  if (ownContribution < MINIMUM_ANNUAL_CONTRIBUTION_FOR_ALLOWANCE) {
    return allowanceBreakdown(ownContribution, 0, 0);
  }

  const firstTierContribution = Math.min(ownContribution, BASE_ALLOWANCE_FIRST_TIER_LIMIT);
  const secondTierContribution = Math.min(
    Math.max(0, ownContribution - BASE_ALLOWANCE_FIRST_TIER_LIMIT),
    BASE_ALLOWANCE_SECOND_TIER_LIMIT - BASE_ALLOWANCE_FIRST_TIER_LIMIT
  );
  const baseAllowance =
    firstTierContribution * BASE_ALLOWANCE_FIRST_TIER_RATE +
    secondTierContribution * BASE_ALLOWANCE_SECOND_TIER_RATE;
  const childAllowance = Math.min(ownContribution, CHILD_ALLOWANCE_LIMIT) * children;

  return allowanceBreakdown(ownContribution, baseAllowance, childAllowance);
}

export function retirementDepotAllowanceForProjectionMonth(
  positions: ReservePosition[],
  settings: InvestmentSettings,
  baseYear: number,
  projectionMonthIndex: number
): number {
  if (!settings.retirementDepotEnabled || !settings.retirementDepotAllowanceEnabled) return 0;

  const monthlyOwnContribution = selectedInvestmentContributionForProjectionMonth(
    positions,
    settings,
    baseYear,
    projectionMonthIndex
  );
  if (monthlyOwnContribution <= 0) return 0;

  const projectionYearIndex = Math.floor(projectionMonthIndex / 12);
  const annualOwnContribution = selectedInvestmentContributionForProjectionYear(
    positions,
    settings,
    baseYear,
    projectionYearIndex
  );
  if (annualOwnContribution <= 0) return 0;

  const allowance = calculateRetirementDepotAllowance(annualOwnContribution, settings.retirementDepotChildren);
  return allowance.totalAllowance * (monthlyOwnContribution / annualOwnContribution);
}

function allowanceBreakdown(
  annualOwnContribution: number,
  baseAllowance: number,
  childAllowance: number
): RetirementDepotAllowance {
  const totalAllowance = baseAllowance + childAllowance;
  return {
    annualOwnContribution,
    baseAllowance,
    childAllowance,
    totalAllowance,
    allowanceRatePercent: annualOwnContribution > 0 ? (totalAllowance / annualOwnContribution) * 100 : 0,
    annualContributionWithAllowance: annualOwnContribution + totalAllowance
  };
}

import { businessIdeaCanvasCardNodes, businessIdeaCanvasNodeText } from "./businessIdeaCanvas";
