export const SELF_EMPLOYMENT_GANTT_DEFAULT_TIME_BUDGET_HOURS = 1;
export const SELF_EMPLOYMENT_GANTT_LABEL_ORDER = ["idea", "knowledge", "start", "implementation", "goal"] as const;

