  host.getState().incomePlanning = {
    ...host.getState().incomePlanning,
    calendarStamps: exists
      ? host.getState().incomePlanning.calendarStamps.map((item) => (item.id === stamp.id ? stamp : item))
      : [...host.getState().incomePlanning.calendarStamps, stamp]
  };
