  if (
    value !== "deductions" &&
    value !== "social" &&
    value !== "taxes" &&
    value !== "income" &&
    value !== "label_distribution"
  ) {
    return;
  }
  incomeTrackerUiState.analysisDataView = value;
  renderIncomeAnalysisDialog(incomeTrackerModel(), host.getState().incomeTracker.yearlyEntries);
