}

.income-analysis-line strong,
.income-analysis-line small {
  font-variant-numeric: tabular-nums;
  white-space: nowrap;
}

.income-analysis-line small {
  color: var(--muted);
  font-weight: 800;
}

.income-analysis-total {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  min-height: 44px;
  border-radius: 8px;
  background: var(--surface-muted);
  padding: 10px;
  font-weight: 900;
}

.income-analysis-label-filter-card {
  min-width: 0;
  border: 1px solid var(--row-border);
  border-radius: 8px;
  background: var(--surface-soft);
  padding: 10px;
}

.income-analysis-label-filter-card {
  display: grid;
  min-height: 58px;
  align-items: center;
}

.income-analysis-label-income-list {
  align-content: start;
  gap: 8px;
}

.income-analysis-label-income-card {
  display: grid;
  grid-template-columns: minmax(0, 1fr) auto;
  align-items: baseline;
  gap: 8px;
  min-width: 0;
  border-bottom: 1px solid var(--row-border);
  padding: 9px 0;
}

.income-analysis-label-income-card span {
  color: var(--muted);
  font-size: 0.76rem;
  font-weight: 850;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.income-analysis-label-income-card strong {
  color: var(--text);
  font-size: 0.96rem;
  font-variant-numeric: tabular-nums;
  font-weight: 950;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.income-analysis-label-filter-row {
  display: flex;
  align-items: center;
  gap: 6px;
  min-height: 38px;
  overflow-x: auto;
  padding-bottom: 2px;
}

.income-analysis-label-filter-button {
  flex: 0 0 34px;
}

.income-analysis-empty {
  display: grid;
  height: 100%;
  min-height: 0;
  place-items: center;
  color: var(--muted);
  font-size: 0.9rem;
  text-align: center;
}

.income-analysis-line .tax,
.income-analysis-legend .tax,
.income-analysis-bar-column .tax,
.income-analysis-svg .tax {
  background: var(--danger);
  stroke: var(--danger);
}

.income-analysis-line .social,
.income-analysis-legend .social,
.income-analysis-bar-column .social,
.income-analysis-svg .social {
  background: #3366cc;
  stroke: #3366cc;
}

.income-analysis-line .net,
.income-analysis-legend .net,
.income-analysis-bar-column .net,
.income-analysis-svg .net {
  background: var(--good);
  stroke: var(--good);
}

.income-analysis-line .gross,
.income-analysis-legend .gross,
.income-analysis-bar-column .gross,
.income-analysis-svg .gross {
  background: #64748b;
  stroke: #64748b;
}

.income-analysis-line .deduction,
.income-analysis-legend .deduction,
.income-analysis-bar-column .deduction,
.income-analysis-svg .deduction {
  background: var(--gold);
  stroke: var(--gold);
}

.income-analysis-line .employer,
.income-analysis-legend .employer,
.income-analysis-bar-column .employer,
.income-analysis-svg .employer {
  background: #0f766e;
  stroke: #0f766e;
}

.income-analysis-line .gold,
.income-analysis-legend .gold,
.income-analysis-bar-column .gold {
  background: #b87514;
}

.income-analysis-line .blue,
.income-analysis-legend .blue,
.income-analysis-bar-column .blue {
  background: #1d4ed8;
}

.income-analysis-line .care,
.income-analysis-legend .care,
.income-analysis-bar-column .care {
  background: #7c3aed;
}

.income-analysis-line .danger,
.income-analysis-legend .danger,
.income-analysis-bar-column .danger,
.income-analysis-svg .danger {
  background: var(--danger);
  stroke: var(--danger);
}

.income-analysis-line .refund,
.income-analysis-legend .refund,
.income-analysis-bar-column .refund,
.income-analysis-svg .refund {
  background: var(--good);
  stroke: var(--good);
}

.income-analysis-line .unassigned,
.income-analysis-legend .unassigned,
.income-analysis-bar-column .unassigned {
  background: #737373;
}

.income-analysis-svg .series-point {
  stroke: var(--surface);
  stroke-width: 2;
}

.income-analysis-svg .series-point.tax {
  fill: var(--danger);
  stroke: var(--surface);
}

.income-analysis-svg .series-point.social {
  fill: #3366cc;
  stroke: var(--surface);
}

.income-analysis-svg .series-point.net {
  fill: var(--good);
  stroke: var(--surface);
}

.income-analysis-svg .series-point.gross {
  fill: #64748b;
  stroke: var(--surface);
}

.income-analysis-svg .series-point.deduction {
  fill: var(--gold);
  stroke: var(--surface);
}

.income-analysis-svg .series-point.employer {
  fill: #0f766e;
  stroke: var(--surface);
}

.income-analysis-svg .series-point.danger {
  fill: var(--danger);
  stroke: var(--surface);
}

.income-analysis-svg .series-point.refund {
  fill: var(--good);
  stroke: var(--surface);
}

.income-chart-host {
  min-height: 230px;
  border: 1px solid var(--row-border);
  border-radius: 8px;
  background: var(--surface);
  padding: 10px;
}

.income-bar-chart,
.income-grouped-chart {
  display: grid;
  grid-template-columns: repeat(var(--income-bar-count, 1), minmax(42px, 1fr));
  gap: 8px;
  min-height: 210px;
}

.income-grouped-chart {
  grid-template-columns: repeat(auto-fit, minmax(58px, 1fr));
}

.income-bar-column,
.income-group {
  display: grid;
  grid-template-rows: 150px auto auto auto;
  gap: 4px;
  min-width: 0;
  text-align: center;
}

.income-bar-track,
.income-paired-bars {
  position: relative;
  display: flex;
  align-items: end;
  justify-content: center;
  gap: 4px;
  min-height: 150px;
  border-bottom: 1px solid var(--row-border);
}

.income-paired-bars .income-bar {
  width: 15px;
}

.income-bar {
  display: block;
  width: min(34px, 70%);
  min-height: 3px;
  border-radius: 5px 5px 0 0;
  background: var(--accent);
}

.income-bar.blue {
  background: #3366cc;
}

.income-bar.gold,
.income-bar.warning {
  background: var(--gold);
}

.income-bar.good {
  background: var(--good);
}

.income-bar.danger,
.income-bar.negative {
  background: var(--danger);
}

.income-bar-column span,
.income-group span {
  color: var(--muted);
  font-size: 0.72rem;
  font-weight: 850;
  overflow: hidden;
  text-overflow: ellipsis;
}

.income-bar-column strong {
  color: var(--text);
  font-size: 0.76rem;
  font-weight: 900;
  overflow-wrap: anywhere;
}

.income-bar-column small {
  color: var(--muted);
  font-size: 0.68rem;
  font-weight: 750;
  min-height: 1em;
  overflow: hidden;
  text-overflow: ellipsis;
}

.income-inflation-values {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.income-inflation-values small {
  display: grid;
  gap: 1px;
  color: var(--muted);
  font-size: 0.66rem;
  font-weight: 750;
  line-height: 1.15;
  overflow-wrap: anywhere;
}

.income-inflation-values b {
  color: var(--text);
  font-size: 0.66rem;
  font-weight: 900;
}

.income-chart-marker {
  position: absolute;
  top: 4px;
  left: 50%;
  transform: translateX(-50%);
  border-radius: 999px;
  background: var(--danger);
  color: #fff;
  padding: 1px 6px;
  font-size: 0.68rem;
  font-weight: 900;
}

.income-projection-chart {
  display: grid;
  gap: 6px;
}

.income-projection-growth-row {
  display: grid;
  grid-template-columns: repeat(var(--income-projection-gap-count, 1), minmax(42px, 1fr));
  gap: 8px;
  min-height: 24px;
}

.income-projection-growth-arrow {
  position: relative;
  display: flex;
  align-items: center;
  justify-content: center;
  min-width: 0;
  color: var(--accent-strong);
  font-size: 0.7rem;
  font-weight: 900;
}

.income-projection-growth-arrow::before {
  position: absolute;
  left: 12%;
  right: 12%;
  top: 50%;
  height: 2px;
  background: var(--accent);
  content: "";
}

.income-projection-growth-arrow::after {
  position: absolute;
  right: 10%;
  top: calc(50% - 4px);
  border-bottom: 4px solid transparent;
  border-left: 7px solid var(--accent);
  border-top: 4px solid transparent;
  content: "";
}

.income-projection-growth-arrow b {
  position: relative;
  z-index: 1;
  border: 1px solid var(--row-border);
  border-radius: 999px;
  background: var(--surface);
  padding: 2px 7px;
  white-space: nowrap;
}

.income-chart-milestone-markers {
  position: absolute;
  top: 3px;
  left: 50%;
  display: flex;
  gap: 3px;
  transform: translateX(-50%);
  z-index: 1;
}

.income-chart-milestone-markers span {
  display: inline-grid;
  width: 24px;
  height: 24px;
  place-items: center;
  border: 1px solid var(--row-border);
  border-radius: 999px;
  background: var(--surface);
  color: var(--accent-strong);
  box-shadow: 0 4px 10px rgba(31, 37, 40, 0.12);
}

.income-chart-milestone-markers svg {
  width: 15px;
  height: 15px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 2;
}

.income-chart-legend {
  display: flex;
  flex-wrap: wrap;
  gap: 12px;
  margin-top: 8px;
  color: var(--muted);
  font-size: 0.76rem;
  font-weight: 800;
}

.income-chart-legend span {
  display: inline-block;
  width: 10px;
  height: 10px;
  border-radius: 999px;
  margin-right: -8px;
}

.income-chart-legend .blue {
  background: #3366cc;
}

.income-chart-legend .gold {
  background: var(--gold);
}

@import "./tracker.css";
@import "./tax-dialog.css";
@import "./charts.css";
@import "./analysis.css";

.income-tax-dialog-backdrop {
  position: fixed;
  z-index: 45;
  inset: 0;
  display: grid;
  place-items: center;
  background: rgba(31, 37, 40, 0.35);
  padding: 16px;
}

.position-cost-dialog-backdrop {
  position: fixed;
  z-index: 45;
  inset: 0;
  display: grid;
  place-items: center;
  background: rgba(31, 37, 40, 0.35);
  padding: 16px;
}

:root[data-theme="dark"] .income-tax-dialog-backdrop {
  background: rgba(0, 0, 0, 0.52);
}

.position-cost-dialog {
  display: grid;
  gap: 12px;
  width: min(680px, 100%);
  max-height: min(720px, calc(100vh - 32px));
