  padding: 12px;
}

:root[data-theme="dark"] .position-cost-dialog-backdrop {
  background: rgba(0, 0, 0, 0.52);
}

.income-tax-dialog {
  display: grid;
  gap: 12px;
  width: min(760px, 100%);
  max-height: min(760px, calc(100vh - 32px));
  overflow: auto;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
