function selfEmploymentCollectionTextField(
  project: SelfEmploymentProject,
  collection: string,
  itemId: string,
  field: string,
  label: string,
  value: string,
  type = "text"
): string {
  return `
    <label class="field self-employment-edit-field">
      <span>${escapeHtml(label)}</span>
      <input type="${escapeHtml(type)}" value="${escapeHtml(value)}" data-self-employment-project-id="${escapeHtml(
        project.id
      )}" data-self-employment-collection="${escapeHtml(collection)}" data-self-employment-item-id="${escapeHtml(
        itemId
      )}" data-self-employment-item-field="${escapeHtml(field)}" />
    </label>
  `;
}

function selfEmploymentCollectionNumberField(
  project: SelfEmploymentProject,
  collection: string,
  itemId: string,
  field: string,
  label: string,
  value: number,
  min: number,
  max: number,
  step: number
): string {
  return `
    <label class="field self-employment-edit-field">
      <span>${escapeHtml(label)}</span>
      <input type="number" min="${min}" max="${max}" step="${step}" value="${value}" data-self-employment-project-id="${escapeHtml(
        project.id
      )}" data-self-employment-collection="${escapeHtml(collection)}" data-self-employment-item-id="${escapeHtml(
        itemId
      )}" data-self-employment-item-field="${escapeHtml(field)}" />
    </label>
  `;
}

function selfEmploymentCollectionSelectField(
  project: SelfEmploymentProject,
  collection: string,
  itemId: string,
  field: string,
  label: string,
  value: string,
  options: Array<[string, string]>
): string {
  return `
    <label class="field self-employment-edit-field">
      <span>${escapeHtml(label)}</span>
      <select data-self-employment-project-id="${escapeHtml(project.id)}" data-self-employment-collection="${escapeHtml(
        collection
      )}" data-self-employment-item-id="${escapeHtml(itemId)}" data-self-employment-item-field="${escapeHtml(field)}">
        ${options.map(([optionValue, optionLabel]) => selfEmploymentOption(optionValue, optionLabel, value)).join("")}
      </select>
    </label>
  `;
}

function selfEmploymentOption(value: string, label: string, selectedValue: string): string {
  return `<option value="${escapeHtml(value)}" ${value === selectedValue ? "selected" : ""}>${escapeHtml(label)}</option>`;
}

.self-employment-dashboard {
  display: grid;
  gap: 16px;
}

.self-employment-hero,
.self-employment-detail-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 12px;
}

.self-employment-hero h2,
.self-employment-detail-head h2 {
  margin: 4px 0 0;
  font-size: 1.22rem;
}

.self-employment-hero-actions {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
  gap: 8px;
}

.self-employment-metrics,
.self-employment-analysis,
.self-employment-tables {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 12px;
}

.self-employment-cards {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(230px, 1fr));
  gap: 12px;
}

.self-employment-project-card {
  display: grid;
  align-content: start;
  gap: 9px;
  min-height: 176px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface-soft);
  color: var(--text);
  padding: 12px;
  text-align: left;
}

.self-employment-project-main {
  display: grid;
  gap: 7px;
  width: 100%;
  border: 0;
  background: transparent;
  color: inherit;
  padding: 0;
  font: inherit;
  text-align: left;
  cursor: pointer;
}

.self-employment-project-card.active {
  border-color: var(--accent);
  box-shadow: inset 0 0 0 1px var(--accent);
}

.self-employment-project-card.realistic {
  background: var(--accent-soft);
}

.self-employment-project-card.borderline {
  background: var(--gold-soft);
}

.self-employment-project-card.unrealistic {
  background: var(--danger-soft);
}

.self-employment-project-head {
  display: grid;
  grid-template-columns: 42px minmax(0, 1fr);
  align-items: start;
  gap: 10px;
}

.self-employment-project-icon-button {
  display: inline-grid;
  width: 42px;
  height: 42px;
  place-items: center;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  color: var(--accent-strong);
  cursor: pointer;
  padding: 0;
}

.self-employment-project-icon-button:hover {
  border-color: var(--accent);
  background: var(--accent-soft);
}

.self-employment-project-icon-svg {
  width: 22px;
  height: 22px;
}

.self-employment-empty-card {
  display: grid;
  gap: 6px;
  border: 1px dashed var(--border);
  border-radius: 8px;
  background: var(--surface-soft);
  color: var(--muted);
  padding: 16px;
}

.self-employment-empty-card h3,
.self-employment-empty-card p {
  margin: 0;
}

.self-employment-project-title {
  display: flex;
  align-items: center;
  gap: 8px;
}

.self-employment-project-title strong {
  font-size: 1rem;
  overflow-wrap: anywhere;
}

.self-employment-project-icon {
  display: grid;
  width: 34px;
  height: 34px;
  place-items: center;
  border-radius: 8px;
  background: var(--surface);
  color: var(--accent-strong);
  font-size: 0.72rem;
  font-weight: 900;
}

.self-employment-project-main > span:not(.self-employment-project-title):not(.self-employment-project-icon) {
  color: var(--muted);
  font-size: 0.82rem;
}

.self-employment-project-labels {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.self-employment-label-chip,
.self-employment-label-option {
  display: inline-flex;
  align-items: center;
  min-height: 24px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: var(--surface);
  color: var(--muted);
  padding: 3px 8px;
  font-size: 0.74rem;
  font-weight: 800;
}

.self-employment-label-chip.muted {
  opacity: 0.72;
}

.self-employment-project-actions,
.self-employment-label-picker {
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.self-employment-project-actions .button {
