}

.self-employment-label-picker {
  border-top: 1px solid var(--border);
  padding-top: 8px;
}

.self-employment-label-option {
  cursor: pointer;
}

.self-employment-label-option.active {
  border-color: var(--accent);
  background: var(--accent-soft);
  color: var(--accent-strong);
}

.self-employment-roadmap {
  display: grid;
  grid-template-columns: repeat(9, minmax(118px, 1fr));
  gap: 8px;
  overflow-x: auto;
  padding-bottom: 4px;
