.self-employment-roadmap-panel h3 {
  margin: 0;
  font-size: 1rem;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.self-employment-roadmap-panel-icon {
  width: 22px;
  height: 22px;
  color: var(--accent-strong);
}

.self-employment-gantt-phase-filter {
  display: flex;
  justify-content: flex-end;
  flex-wrap: wrap;
  gap: 6px;
  margin-left: auto;
}

.self-employment-gantt-phase-filter-button {
  display: inline-grid;
  place-items: center;
  width: 32px;
  height: 32px;
  border: 1px solid var(--border);
  border-radius: 50%;
  background: var(--surface);
  color: var(--muted);
  cursor: pointer;
  font: inherit;
  font-size: 0.82rem;
  font-weight: 950;
  line-height: 1;
  padding: 0;
}

.self-employment-gantt-phase-filter-button:hover,
.self-employment-gantt-phase-filter-button:focus-visible {
  border-color: var(--accent-strong);
  color: var(--accent-strong);
  outline: 2px solid color-mix(in srgb, var(--accent-strong) 25%, transparent);
  outline-offset: 2px;
}

.self-employment-gantt-phase-filter-button.active {
  border-color: var(--accent-strong);
  background: var(--accent-soft);
  color: var(--accent-strong);
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--accent-strong) 18%, transparent);
}

@media (max-width: 640px) {
  .self-employment-gantt-phase-filter {
    width: 100%;
  }
}

.self-employment-edit-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(220px, 1fr));
  gap: 10px;
}

.self-employment-edit-grid.compact {
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
}

.self-employment-edit-field.wide {
  grid-column: 1 / -1;
}

.self-employment-edit-field textarea {
  min-height: 88px;
  resize: vertical;
}

.self-employment-readonly-field {
  justify-content: start;
  min-height: 70px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  padding: 10px;
}

.self-employment-readonly-field strong {
  overflow-wrap: anywhere;
}

.self-employment-project-gantt {
  display: grid;
  gap: 10px;
  min-width: 0;
}

.self-employment-project-gantt-summary {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
}

.self-employment-project-gantt-summary span {
  display: inline-flex;
  align-items: baseline;
  gap: 5px;
  border: 1px solid var(--border);
  border-radius: 8px;
