  color: var(--text);
}

.self-employment-project-gantt-head,
.self-employment-project-gantt-row {
  display: grid;
  grid-template-columns: minmax(150px, 0.8fr) 86px minmax(260px, 2.2fr);
  align-items: center;
  gap: 8px;
}

.self-employment-project-gantt-head {
  color: var(--muted);
  font-size: 0.72rem;
  font-weight: 900;
  text-transform: uppercase;
}

.self-employment-project-gantt-rows {
