  gap: 8px;
  min-width: 0;
}

.self-employment-project-gantt-row {
  min-width: 0;
}

.self-employment-project-gantt-phase {
  display: grid;
  grid-template-columns: 34px minmax(0, 1fr);
  align-items: center;
  gap: 8px;
  min-width: 0;
  min-height: 54px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  color: var(--text);
  cursor: pointer;
  font: inherit;
  padding: 8px;
  text-align: left;
}

.self-employment-project-gantt-phase:hover,
.self-employment-project-gantt-phase:focus-visible {
  border-color: var(--accent-strong);
  background: var(--surface-soft);
}

.self-employment-project-gantt-phase-badge {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 28px;
  height: 28px;
  border-radius: 50%;
  background: var(--accent-soft);
  color: var(--accent-strong);
  font-size: 0.86rem;
  font-weight: 950;
  line-height: 1;
}

.self-employment-project-gantt-phase strong,
.self-employment-project-gantt-phase small {
  display: block;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.self-employment-project-gantt-phase small,
.self-employment-project-gantt-hours small {
  color: var(--muted);
  font-size: 0.72rem;
  font-weight: 850;
}

.self-employment-project-gantt-hours {
  display: grid;
  gap: 2px;
  align-content: center;
  min-height: 54px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  padding: 8px;
}

.self-employment-project-gantt-hours strong {
  font-size: 0.86rem;
}

.self-employment-project-gantt-row.disabled {
  opacity: 0.62;
}

.self-employment-project-gantt-track {
  position: relative;
  height: 58px;
  min-width: 0;
  overflow: hidden;
  border: 1px solid var(--border);
  border-radius: 8px;
  background:
    repeating-linear-gradient(90deg, transparent 0, transparent calc(10% - 1px), var(--row-border) calc(10% - 1px), var(--row-border) 10%),
    var(--surface);
}

.self-employment-project-gantt-label {
  position: absolute;
  top: 6px;
  bottom: 6px;
  display: grid;
  grid-template-rows: auto minmax(0, 1fr);
  min-width: 4px;
  overflow: hidden;
  border-radius: 7px;
  background: color-mix(in srgb, var(--self-employment-gantt-color) 74%, transparent);
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--self-employment-gantt-color) 42%, var(--border));
}

.self-employment-project-gantt-label-head {
  display: flex;
  justify-content: space-between;
  gap: 6px;
  min-width: 0;
  color: white;
  font-size: 0.68rem;
  font-weight: 950;
  line-height: 1;
  padding: 5px 6px 3px;
  text-shadow: 0 1px 1px rgba(15, 23, 42, 0.24);
}

.self-employment-project-gantt-label-head span,
.self-employment-project-gantt-label-head strong {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.self-employment-project-gantt-cards {
  display: flex;
  gap: 2px;
  min-width: 0;
  overflow: hidden;
  padding: 0 4px 4px;
}

.self-employment-project-gantt-card {
  min-width: 30px;
  overflow: hidden;
  border: 1px solid color-mix(in srgb, white 42%, transparent);
  border-radius: 5px;
  background: color-mix(in srgb, var(--surface) 90%, transparent);
  color: var(--text);
  cursor: pointer;
  font: inherit;
  padding: 2px 4px;
  text-align: left;
}

.self-employment-project-gantt-card:hover,
.self-employment-project-gantt-card:focus-visible {
  background: var(--surface);
  outline: 2px solid color-mix(in srgb, var(--accent-strong) 35%, transparent);
  outline-offset: -1px;
}

.self-employment-project-gantt-card span,
.self-employment-project-gantt-card small {
  display: block;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.self-employment-project-gantt-card span {
  font-size: 0.67rem;
  font-weight: 900;
}

.self-employment-project-gantt-card small {
  color: var(--muted);
  font-size: 0.62rem;
  font-weight: 850;
}

.self-employment-project-gantt-empty {
  position: absolute;
  top: 50%;
  left: 10px;
  right: 10px;
  height: 2px;
  overflow: visible;
  background: var(--row-border);
  color: var(--muted);
  font-size: 0.72rem;
  font-weight: 850;
  line-height: 1;
}

.self-employment-gantt-popover {
  position: fixed;
  z-index: 80;
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
  gap: 10px;
  width: min(560px, calc(100vw - 24px));
  max-height: min(72vh, calc(100vh - 24px));
  overflow: auto;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  box-shadow: 0 18px 42px rgba(15, 23, 42, 0.16);
  overscroll-behavior: contain;
  padding: 12px;
}

.self-employment-gantt-popover > header,
.self-employment-gantt-popover-summary {
  grid-column: 1 / -1;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
}

.self-employment-gantt-popover > header strong {
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.self-employment-gantt-popover-summary {
  justify-content: flex-start;
  color: var(--muted);
  font-size: 0.78rem;
  font-weight: 850;
}

.self-employment-gantt-check {
  min-height: 70px;
}

.self-employment-gantt-check input {
  width: 18px;
  height: 18px;
}

.self-employment-collection-editor {
  display: grid;
  gap: 10px;
}

.self-employment-collection-head,
.self-employment-collection-item > header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 8px;
}

.self-employment-collection-head span {
  color: var(--muted);
  font-size: 0.82rem;
  font-weight: 900;
}

.self-employment-collection-list {
  display: grid;
  gap: 10px;
}

.self-employment-collection-item {
  display: grid;
  gap: 10px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  padding: 10px;
}

.self-employment-empty-note {
  margin: 0;
  color: var(--muted);
  font-weight: 750;
}

.self-employment-chart-card,
.self-employment-table-card {
  display: grid;
  gap: 10px;
  min-width: 0;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface-soft);
  padding: 12px;
}

.self-employment-chart-card h3,
.self-employment-table-card h3 {
  margin: 0;
  font-size: 0.95rem;
}

.self-employment-donut {
  width: 132px;
  aspect-ratio: 1;
  justify-self: center;
  border: 10px solid var(--surface);
  border-radius: 50%;
}

.self-employment-legend,
.self-employment-feasibility-list {
  display: grid;
  gap: 7px;
}

.self-employment-legend span,
.self-employment-feasibility-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  color: var(--muted);
  font-size: 0.82rem;
}

.self-employment-legend i {
  display: inline-block;
  width: 10px;
  height: 10px;
  margin-right: 6px;
  border-radius: 50%;
}

.self-employment-legend i.realistic,
.self-employment-feasibility-item.realistic span {
  color: var(--accent-strong);
}

.self-employment-legend i.realistic {
  background: var(--accent);
}

.self-employment-legend i.borderline {
  background: var(--gold);
}

.self-employment-legend i.unrealistic {
  background: var(--danger);
}

.self-employment-feasibility-item {
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  padding: 9px;
}

.self-employment-feasibility-item.borderline span {
  color: var(--gold);
}

.self-employment-feasibility-item.unrealistic span {
  color: var(--danger);
}

.self-employment-bars {
  display: grid;
  gap: 9px;
}

.self-employment-bar-row {
  display: grid;
  grid-template-columns: minmax(90px, 1fr) minmax(100px, 2fr) minmax(70px, auto);
  align-items: center;
  gap: 8px;
  color: var(--muted);
  font-size: 0.82rem;
}

.self-employment-bar-row div {
  height: 9px;
  overflow: hidden;
  border-radius: 8px;
  background: var(--row-border);
}

.self-employment-bar-row i {
  display: block;
  height: 100%;
  border-radius: 8px;
  background: var(--accent);
}

.self-employment-table-card {
  overflow-x: auto;
}

.self-employment-table-card table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.84rem;
}

.self-employment-table-card th,
.self-employment-table-card td {
  border-bottom: 1px solid var(--border);
  padding: 8px 6px;
  text-align: left;
  white-space: nowrap;
}

.self-employment-detail {
  display: grid;
  gap: 12px;
}

