import { defaultStatutoryPensionSettings } from "../../data/defaults";
import { STATUTORY_PENSION_DEDUCTION_PERCENT_MAX } from "../../domain/statutoryPension";
import type {
  StatutoryPensionIncomeMode,
  StatutoryPensionScenarioId,
  StatutoryPensionScenarioSettings,
  StatutoryPensionSettings
} from "../../types";
import { clampNumber, isRecord, numberOrDefault } from "./validators";

export function normalizeStatutoryPensionScenarioId(
  value: unknown,
  fallback: StatutoryPensionScenarioId
): StatutoryPensionScenarioId {
  return value === "pessimistic" || value === "base" || value === "optimistic" ? value : fallback;
}

export function normalizeStatutoryPensionSettings(value: unknown): StatutoryPensionSettings {
  const fallback = defaultStatutoryPensionSettings();
  if (!isRecord(value)) return fallback;
  return {
    contributionRatePercent: statutoryPensionNumberOrFallback(
      value.contributionRatePercent,
      fallback.contributionRatePercent
    ),
    averageAnnualIncome: statutoryPensionNumberOrFallback(value.averageAnnualIncome, fallback.averageAnnualIncome),
    currentPensionValue: statutoryPensionNumberOrFallback(value.currentPensionValue, fallback.currentPensionValue),
    projectionPensionValue: statutoryPensionNumberOrFallback(
      value.projectionPensionValue,
      fallback.projectionPensionValue
    ),
    annualContributionCeilingGross: statutoryPensionNumberOrFallback(
      value.annualContributionCeilingGross,
      fallback.annualContributionCeilingGross
    ),
    scenarios: {
      pessimistic: normalizeStatutoryPensionScenario(value.scenarios, "pessimistic", fallback.scenarios.pessimistic),
      base: normalizeStatutoryPensionScenario(value.scenarios, "base", fallback.scenarios.base),
      optimistic: normalizeStatutoryPensionScenario(value.scenarios, "optimistic", fallback.scenarios.optimistic)
    }
  };
}

export function normalizeStatutoryPensionScenario(
  scenarios: unknown,
  id: StatutoryPensionScenarioId,
  fallback: StatutoryPensionScenarioSettings
): StatutoryPensionScenarioSettings {
  const value = isRecord(scenarios) && isRecord(scenarios[id]) ? scenarios[id] : {};
  const useDeductionFallbacks = statutoryPensionUsesDeductionFallbacks(value);
  return {
    retirementAge: clampNumber(statutoryPensionNumberOrFallback(value.retirementAge, fallback.retirementAge), 67, 72),
    incomeMode: normalizeStatutoryPensionIncomeMode(value.incomeMode, fallback.incomeMode),
    annualPensionIncreasePercent: clampNumber(
      statutoryPensionNumberOrFallback(
        value.annualPensionIncreasePercent,
        fallback.annualPensionIncreasePercent
      ),
      0.1,
      2
    ),
    taxRatePercent: clampNumber(
      useDeductionFallbacks
        ? fallback.taxRatePercent
        : statutoryPensionNumberOrFallback(value.taxRatePercent, fallback.taxRatePercent),
      0,
      STATUTORY_PENSION_DEDUCTION_PERCENT_MAX
    ),
    healthInsurancePercent: clampNumber(
      useDeductionFallbacks
        ? fallback.healthInsurancePercent
        : statutoryPensionNumberOrFallback(value.healthInsurancePercent, fallback.healthInsurancePercent),
      0,
      STATUTORY_PENSION_DEDUCTION_PERCENT_MAX
    ),
    careInsurancePercent: clampNumber(
      useDeductionFallbacks
        ? fallback.careInsurancePercent
        : statutoryPensionNumberOrFallback(value.careInsurancePercent, fallback.careInsurancePercent),
      0,
      STATUTORY_PENSION_DEDUCTION_PERCENT_MAX
    )
  };
}

export function statutoryPensionNumberOrFallback(value: unknown, fallback: number): number {
  if (value === null || value === undefined || value === "") return fallback;
  return numberOrDefault(value, fallback);
}

export function statutoryPensionUsesDeductionFallbacks(value: Record<string, unknown>): boolean {
  return (
    statutoryPensionSavedNumber(value.healthInsurancePercent) === 0 &&
    statutoryPensionSavedNumber(value.careInsurancePercent) === 0
  );
}

export function statutoryPensionSavedNumber(value: unknown): number | null {
  if (value === null || value === undefined || value === "") return null;
  const parsed = Number(String(value).replace(",", "."));
  return Number.isFinite(parsed) ? parsed : null;
}

export function normalizeStatutoryPensionIncomeMode(
  value: unknown,
  fallback: StatutoryPensionIncomeMode
): StatutoryPensionIncomeMode {
  return value === "constant" || value === "income_projection" ? value : fallback;
}

import { defaultAppState } from "../../data/defaults";
import type { AppState } from "../../types";
import { saveFallbackStateValue } from "../vault/vaultFallback";
import { stageVaultSave } from "./vaultRuntime";

export function saveState(state: AppState, storage: Storage = localStorage): void {
  saveFallbackStateValue(state, storage);
  stageVaultSave(state);
}

export function resetStoredState(storage: Storage = localStorage): AppState {
  const state = defaultAppState();
  saveState(state, storage);
  return state;
}

export function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

export function numberOrDefault(value: unknown, fallback: number): number {
  const parsed = Number(String(value ?? "").replace(",", "."));
  return Number.isFinite(parsed) ? parsed : fallback;
}

export function clampNumber(value: number, min: number, max: number): number {
  return Math.min(max, Math.max(min, value));
}

export function nullableNumberOrDefault(value: unknown, fallback: number | null): number | null {
  if (value === null || value === undefined || value === "") return fallback;
  const parsed = Number(String(value).replace(",", "."));
  return Number.isFinite(parsed) ? parsed : fallback;
}

export function stringArrayOrDefault(value: unknown, fallback: string[]): string[] {
  if (!Array.isArray(value)) return fallback;
  return value.map(String);
}

export function booleanOrDefault(value: unknown, fallback: boolean): boolean {
  if (typeof value === "boolean") return value;
  return fallback;
}

export function normalizePlanningYearSelection(value: unknown, fallback: number | null): number | null {
  if (value === null || value === undefined || value === "" || value === "start") return null;
  const parsed = Math.round(numberOrDefault(value, Number.NaN));
  return Number.isFinite(parsed) && parsed >= 2000 && parsed <= 2200 ? parsed : fallback;
}

export function arrayOrEmpty(value: unknown): unknown[] {
  return Array.isArray(value) ? value : [];
}

import { defaultAppState } from "../../data/defaults";
import type { AppState } from "../../types";
import {
  readVaultFallbackMetadata,
  saveFallbackStateValue,
  saveVaultFallbackMetadata
} from "../vault/vaultFallback";
import {
  createVaultSnapshot,
  isVaultRuntimeAvailable,
  pickVaultDirectory,
  profilePath as vaultProfilePath,
  readVaultState,
  writeVaultState
} from "../vault/vaultStorage";
import type { VaultRuntimeState, VaultSnapshotResult } from "../vault/vaultTypes";
import { loadState } from "./loadState";
import { normalizeState } from "./normalizeState";

let vaultRuntimeState: VaultRuntimeState = {
  status: "disconnected",
  vaultRootPath: null,
  profilePath: null,
  lastSavedAt: null,
  lastError: null,
  pendingWrites: 0
};
let vaultPendingState: AppState | null = null;
let vaultWriteScheduled = false;
let vaultWriteQueue: Promise<void> = Promise.resolve();

export async function initializeStorage(storage: Storage = localStorage): Promise<AppState> {
  let fallback = defaultAppState();
  try {
    fallback = loadState(storage);
  } catch (error) {
    console.warn("Fallback state could not be loaded.", error);
  }
  if (!isVaultRuntimeAvailable()) {
    vaultRuntimeState = {
      status: "csvOnly",
      vaultRootPath: null,
      profilePath: null,
      lastSavedAt: null,
      lastError: null,
      pendingWrites: 0
    };
    return fallback;
  }

  const metadata = safeReadVaultFallbackMetadata(storage);
  if (!metadata) {
    vaultRuntimeState = {
      status: "disconnected",
      vaultRootPath: null,
      profilePath: null,
      lastSavedAt: null,
      lastError: null,
      pendingWrites: 0
    };
    return fallback;
  }

  try {
    const vaultState = normalizeState(await readVaultState(metadata.vaultRootPath));
    saveFallbackStateValue(vaultState, storage);
    setVaultConnected(metadata.vaultRootPath, metadata.updatedAt);
    return vaultState;
  } catch (error) {
    setVaultError(metadata.vaultRootPath, error);
    return fallback;
  }
}

export function getVaultStatus(): VaultRuntimeState {
  return { ...vaultRuntimeState };
}

export async function selectVault(state: AppState, storage: Storage = localStorage): Promise<VaultRuntimeState> {
  return activatePickedVault("Vault auswaehlen", state, storage);
}

export async function createVault(state: AppState, storage: Storage = localStorage): Promise<VaultRuntimeState> {
  return activatePickedVault("Neuen Vault erstellen", state, storage);
}

export async function reloadFromVault(storage: Storage = localStorage): Promise<AppState | null> {
  const rootPath = vaultRuntimeState.vaultRootPath;
  if (!rootPath || vaultRuntimeState.status === "csvOnly") return null;

  try {
    const vaultState = normalizeState(await readVaultState(rootPath));
    saveFallbackStateValue(vaultState, storage);
    saveVaultFallbackMetadata(rootPath, storage);
    setVaultConnected(rootPath, vaultRuntimeState.lastSavedAt);
    return vaultState;
  } catch (error) {
    setVaultError(rootPath, error);
    return null;
  }
}

export async function flushVaultSave(state: AppState, storage: Storage = localStorage): Promise<VaultRuntimeState> {
  saveFallbackStateValue(state, storage);
  const rootPath = vaultRuntimeState.vaultRootPath;
  if (!rootPath || vaultRuntimeState.status === "csvOnly") return getVaultStatus();

  vaultPendingState = state;
  queueVaultSave();
  await vaultWriteQueue;
  return getVaultStatus();
}

export async function snapshotVault(): Promise<VaultSnapshotResult | null> {
  const rootPath = vaultRuntimeState.vaultRootPath;
  if (!rootPath || vaultRuntimeState.status === "csvOnly") return null;

  try {
    return await createVaultSnapshot(rootPath);
  } catch (error) {
    setVaultError(rootPath, error);
    return null;
  }
}

export function stageVaultSave(state: AppState): void {
  if (vaultRuntimeState.status === "connected" && vaultRuntimeState.vaultRootPath) {
    vaultPendingState = state;
    queueVaultSave();
  }
}

async function activatePickedVault(
  title: string,
  state: AppState,
  storage: Storage
): Promise<VaultRuntimeState> {
  if (!isVaultRuntimeAvailable()) {
    vaultRuntimeState = {
      status: "csvOnly",
      vaultRootPath: null,
      profilePath: null,
      lastSavedAt: null,
      lastError: null,
      pendingWrites: 0
    };
    return getVaultStatus();
  }

  const selectedPath = await pickVaultDirectory(title);
  if (!selectedPath) return getVaultStatus();

  try {
    const result = await writeVaultState(selectedPath, state);
    saveFallbackStateValue(state, storage);
    saveVaultFallbackMetadata(selectedPath, storage);
    setVaultConnected(selectedPath, result.savedAt);
    return getVaultStatus();
  } catch (error) {
    setVaultError(selectedPath, error);
    return getVaultStatus();
  }
}

function queueVaultSave(): void {
  if (!vaultRuntimeState.vaultRootPath || vaultRuntimeState.status === "csvOnly") return;
  vaultRuntimeState = { ...vaultRuntimeState, pendingWrites: 1 };
  if (vaultWriteScheduled) return;

  vaultWriteScheduled = true;
  vaultWriteQueue = vaultWriteQueue.then(processQueuedVaultSave);
}

async function processQueuedVaultSave(): Promise<void> {
  const rootPath = vaultRuntimeState.vaultRootPath;
  if (!rootPath) {
    vaultWriteScheduled = false;
    vaultRuntimeState = { ...vaultRuntimeState, pendingWrites: 0 };
    return;
  }

  try {
    while (vaultPendingState) {
      const stateToSave = vaultPendingState;
      vaultPendingState = null;
      const result = await writeVaultState(rootPath, stateToSave);
      setVaultConnected(rootPath, result.savedAt);
    }
  } catch (error) {
    setVaultError(rootPath, error);
  } finally {
    vaultWriteScheduled = false;
    vaultRuntimeState = { ...vaultRuntimeState, pendingWrites: vaultPendingState ? 1 : 0 };
    if (vaultPendingState && vaultRuntimeState.status === "connected") queueVaultSave();
  }
}

function setVaultConnected(rootPath: string, lastSavedAt: string | null): void {
  vaultRuntimeState = {
    status: "connected",
    vaultRootPath: rootPath,
    profilePath: vaultProfilePath(rootPath),
    lastSavedAt,
    lastError: null,
    pendingWrites: vaultPendingState || vaultWriteScheduled ? 1 : 0
  };
}

function setVaultError(rootPath: string | null, error: unknown): void {
  vaultRuntimeState = {
    status: "error",
    vaultRootPath: rootPath,
    profilePath: rootPath ? vaultProfilePath(rootPath) : null,
    lastSavedAt: vaultRuntimeState.lastSavedAt,
    lastError: error instanceof Error ? error.message : String(error),
    pendingWrites: 0
  };
}

function safeReadVaultFallbackMetadata(storage: Storage): ReturnType<typeof readVaultFallbackMetadata> {
  try {
    return readVaultFallbackMetadata(storage);
  } catch (error) {
    console.warn("Vault metadata could not be read.", error);
    return null;
  }
}

export const APP_STORAGE_KEY = "blobfin.reserveCalculator.v1";
export const LEGACY_APP_STORAGE_KEY = "jahreskalkulatorState";
export const VAULT_FALLBACK_METADATA_KEY = "blobfin.vault.v1";

export interface VaultFallbackMetadata {
  vaultRootPath: string;
  updatedAt: string;
}

export function readFallbackStateValue(storage: Storage): unknown | null {
  const saved = storage.getItem(APP_STORAGE_KEY);
  if (saved) return JSON.parse(saved);

  const legacy = storage.getItem(LEGACY_APP_STORAGE_KEY);
  if (legacy) return JSON.parse(legacy);

  return null;
}

export function saveFallbackStateValue(value: unknown, storage: Storage): void {
  storage.setItem(APP_STORAGE_KEY, JSON.stringify(value));
}

export function readVaultFallbackMetadata(storage: Storage): VaultFallbackMetadata | null {
  const saved = storage.getItem(VAULT_FALLBACK_METADATA_KEY);
  if (!saved) return null;
  const parsed = JSON.parse(saved);
  if (!isRecord(parsed) || typeof parsed.vaultRootPath !== "string" || !parsed.vaultRootPath) return null;
  return {
    vaultRootPath: parsed.vaultRootPath,
    updatedAt: typeof parsed.updatedAt === "string" ? parsed.updatedAt : new Date().toISOString()
  };
}

export function saveVaultFallbackMetadata(vaultRootPath: string, storage: Storage): VaultFallbackMetadata {
  const metadata = {
    vaultRootPath,
    updatedAt: new Date().toISOString()
  };
  storage.setItem(VAULT_FALLBACK_METADATA_KEY, JSON.stringify(metadata));
  return metadata;
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value && typeof value === "object" && !Array.isArray(value));
}

import {
  VAULT_APP_NAME,
  VAULT_DATA_FILE_PATHS,
  VAULT_PROFILE_FOLDER,
  VAULT_VERSION,
  type VaultDataFileKey,
  type VaultManifest
} from "./vaultTypes";

export function createVaultManifest(createdAt = new Date().toISOString()): VaultManifest {
  return {
    app: VAULT_APP_NAME,
    vaultVersion: VAULT_VERSION,
    createdAt,
    updatedAt: createdAt,
    profileFolder: VAULT_PROFILE_FOLDER,
    dataFiles: { ...VAULT_DATA_FILE_PATHS }
  };
}

export function updateVaultManifestTimestamp(manifest: VaultManifest, updatedAt = new Date().toISOString()): VaultManifest {
  return {
    ...manifest,
    updatedAt,
    dataFiles: { ...VAULT_DATA_FILE_PATHS, ...manifest.dataFiles }
  };
}

export function parseVaultManifest(value: unknown): VaultManifest {
  if (!isRecord(value)) {
    throw new Error("blobfin.json ist keine gueltige Manifest-Datei.");
  }
  if (value.app !== VAULT_APP_NAME) {
    throw new Error("blobfin.json gehoert nicht zu BlobFin.");
  }
  if (value.profileFolder !== VAULT_PROFILE_FOLDER) {
    throw new Error("blobfin.json verweist auf einen unerwarteten Profilordner.");
  }
  if (value.vaultVersion !== VAULT_VERSION) {
    throw new Error(`Vault-Version ${String(value.vaultVersion)} wird nicht unterstuetzt.`);
  }

  const dataFiles = isRecord(value.dataFiles) ? value.dataFiles : {};
  return {
    app: VAULT_APP_NAME,
    vaultVersion: VAULT_VERSION,
    createdAt: stringOrNow(value.createdAt),
    updatedAt: stringOrNow(value.updatedAt),
    profileFolder: VAULT_PROFILE_FOLDER,
    dataFiles: {
      ...VAULT_DATA_FILE_PATHS,
      ...(dataFiles as Partial<Record<VaultDataFileKey, string>>)
    }
  };
}

function stringOrNow(value: unknown): string {
  return typeof value === "string" && value.length > 0 ? value : new Date().toISOString();
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value && typeof value === "object" && !Array.isArray(value));
}

import { parseVaultManifest } from "./vaultManifest";
import type { VaultManifest } from "./vaultTypes";

export function migrateVaultManifest(value: unknown): VaultManifest {
  return parseVaultManifest(value);
}

