.position-icon-picker {
  position: fixed;
  z-index: 120;
  width: min(320px, calc(100vw - 24px));
  max-height: min(360px, calc(100vh - 24px));
  overflow: auto;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  box-shadow: 0 18px 44px rgba(31, 37, 40, 0.2);
  padding: 10px;
}

:root[data-theme="dark"] .position-icon-picker {
  box-shadow: 0 18px 44px rgba(0, 0, 0, 0.45);
}

.position-icon-picker-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  margin-bottom: 10px;
}

.position-icon-picker-head span {
  color: var(--muted);
  font-size: 0.78rem;
  font-weight: 900;
  text-transform: uppercase;
}


.income-year-label-picker {
  width: min(500px, calc(100vw - 24px));
  max-height: min(480px, calc(100vh - 24px));
}

.income-year-label-grid {
  grid-template-columns: repeat(auto-fit, minmax(190px, 1fr));
}

.position-icon-option {
  display: grid;
  grid-template-columns: 28px minmax(0, 1fr);
  align-items: center;
  gap: 8px;
  min-width: 0;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface-soft);
  color: var(--text);
  padding: 8px;
  text-align: left;
  cursor: pointer;
}

.position-icon-option span {
  overflow: hidden;
  font-size: 0.82rem;
  font-weight: 850;
  text-overflow: ellipsis;
}

.income-year-label-option small {
  grid-column: 2;
  color: var(--muted);
  font-size: 0.7rem;
  font-weight: 750;
  line-height: 1.25;
}

.income-year-label-option.active small {
  color: rgba(255, 255, 255, 0.78);
}

.position-icon-option.active {
  border-color: var(--accent);
  background: var(--accent);
  color: #fff;
}

.date-detail-cell {
  display: grid;
  gap: 5px;
  min-width: 132px;
}

.month-col {
  width: 112px;
  min-width: 112px;
}

.result-compact-col {
  width: 112px;
  min-width: 112px;
}

.result-max-needed-col {
  width: 132px;
  min-width: 132px;
  background: var(--highlight);
  color: var(--accent-strong);
  font-weight: 850;
}

.result-permanent-col {
  width: 112px;
  min-width: 112px;
  background: var(--gold-soft);
  color: var(--gold);
  font-weight: 850;
}

.result-interest-col {
  width: 94px;
  min-width: 94px;
}

.split-header {
  display: grid;
  gap: 1px;
  line-height: 1.05;
}

.split-header span {
  display: block;
}

.result-position-heading {
  display: inline-grid;
  justify-items: center;
  gap: 3px;
  min-width: 54px;
}

.result-position-heading .position-icon-svg {
  width: 19px;
  height: 19px;
  color: var(--accent-strong);
}

@layer tokens, reset, base, layout, components, features, utilities, responsive;

@import "./tokens.css" layer(tokens);
@import "./reset.css" layer(reset);
@import "./base.css" layer(base);
@import "./layout.css" layer(layout);

@import "./components/fields.css" layer(components);
@import "./components/buttons.css" layer(components);
@import "./components/popovers.css" layer(components);
@import "./components/details.css" layer(components);

@import "../features/settings/styles.css" layer(features);
@import "../features/planning/styles.css" layer(features);
@import "../features/positions/styles.css" layer(features);
@import "../features/investment/styles.css" layer(features);
@import "../features/real-estate/styles.css" layer(features);
@import "../features/statutory-pension/styles.css" layer(features);
@import "../features/combined-wealth/styles.css" layer(features);
@import "../features/income-tracker/styles.css" layer(features);
@import "../features/income-planning/styles.css" layer(features);
@import "../features/income-stamp-planner/styles.css" layer(features);
@import "../features/self-employment/styles.css" layer(features);
@import "../features/self-employment/business-canvas/styles.css" layer(features);

@import "./utilities.css" layer(utilities);
@import "./responsive.css" layer(responsive);

.app-header {
  display: flex;
  align-items: end;
  justify-content: space-between;
  gap: 24px;
  max-width: 1680px;
  margin: 0 auto;
  padding: 30px 20px 16px;
}

.eyebrow {
  margin: 0 0 4px;
  color: var(--accent-strong);
  font-size: 0.78rem;
  font-weight: 800;
  letter-spacing: 0.08em;
  text-transform: uppercase;
}

h1,
h2,
h3,
p {
  margin-top: 0;
}

h1 {
  margin-bottom: 0;
  font-size: clamp(1.7rem, 2.8vw, 2.8rem);
  letter-spacing: 0;
}

h2 {
  margin-bottom: 0;
  font-size: 1.05rem;
}

h3 {
  margin-bottom: 12px;
  font-size: 0.94rem;
}

.app-main {
  display: grid;
  gap: 16px;
  max-width: 1680px;
  margin: 0 auto;
  padding: 0 20px 42px;
}

.workspace-grid {
  display: grid;
  grid-template-columns: minmax(260px, 380px) minmax(0, 1fr);
  gap: 16px;
}

.panel {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  box-shadow: var(--shadow);
  padding: 16px;
  min-width: 0;
}

.section-heading {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 14px;
}

.button-row,
.header-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.landing-page {
  display: grid;
  gap: 16px;
}

.landing-hero {
  position: relative;
  min-height: 320px;
  overflow: hidden;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface);
  box-shadow: var(--shadow);
  padding: 44px;
}

.landing-hero-actions {
  position: absolute;
  top: 20px;
  right: 20px;
  z-index: 3;
}

.landing-base-data-button {
  box-shadow: var(--shadow);
}

.base-data-popup {
  position: fixed;
  top: 112px;
  right: max(20px, calc((100vw - 1680px) / 2 + 20px));
  z-index: 1000;
  max-height: calc(100vh - 136px);
  overflow: auto;
}

.landing-hero::before {
  content: "";
  position: absolute;
  inset: 0;
  background:
    linear-gradient(110deg, rgba(31, 122, 104, 0.16), transparent 48%),
    linear-gradient(180deg, transparent, var(--surface));
  pointer-events: none;
}

.landing-hero-copy {
  position: relative;
  z-index: 1;
  display: grid;
  gap: 12px;
  max-width: 720px;
  min-height: 230px;
  align-content: center;
}

.landing-hero-copy h2 {
  color: var(--text);
  font-size: 2.65rem;
  line-height: 1;
}

.landing-hero-copy p:last-child {
  max-width: 620px;
  color: var(--muted);
  font-size: 1.02rem;
  font-weight: 750;
}

.landing-hero-graphic {
  position: absolute;
  right: 34px;
  bottom: 24px;
  width: min(44%, 560px);
  min-width: 360px;
  height: 250px;
  opacity: 0.96;
}

.landing-dashboard {
  position: absolute;
  right: 0;
  bottom: 0;
  display: grid;
  gap: 14px;
  width: 78%;
  height: 210px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--metric-bg);
  box-shadow: var(--shadow);
  padding: 18px;
}

.landing-dashboard-line {
  display: block;
  width: 52%;
  height: 9px;
  border-radius: 999px;
  background: var(--row-border);
}

.landing-dashboard-line.wide {
  width: 76%;
  background: var(--accent-soft);
}

.landing-bars {
  display: grid;
  align-items: end;
  grid-template-columns: repeat(4, 1fr);
  gap: 10px;
  height: 88px;
}

.landing-bars span {
  display: block;
  border-radius: 6px 6px 2px 2px;
  background: var(--accent);
}

.landing-bars span:nth-child(1) {
  height: 42%;
}

.landing-bars span:nth-child(2) {
  height: 68%;
  background: var(--gold);
}

.landing-bars span:nth-child(3) {
  height: 86%;
  background: #4d83d8;
}

.landing-bars span:nth-child(4) {
  height: 58%;
  background: var(--reserve);
}

.landing-mini-grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 8px;
}

.landing-mini-grid span {
  height: 28px;
  border: 1px solid var(--row-border);
  border-radius: 6px;
  background: var(--surface-soft);
}

.landing-property-mark {
  position: absolute;
  left: 0;
  bottom: 28px;
  width: 128px;
  height: 128px;
  border: 1px solid var(--border);
  border-radius: 8px;
  background: var(--surface-soft);
  transform: rotate(-2deg);
}

.landing-property-mark::before,
.landing-property-mark::after,
.landing-property-mark span {
  content: "";
  position: absolute;
  background: var(--accent-strong);
}

.landing-property-mark::before {
  left: 28px;
  top: 44px;
  width: 72px;
  height: 58px;
  clip-path: polygon(0 34%, 50% 0, 100% 34%, 100% 100%, 0 100%);
}

.landing-property-mark::after {
  left: 56px;
  bottom: 26px;
  width: 18px;
  height: 28px;
  background: var(--surface-soft);
}

.landing-property-mark span {
  right: 24px;
  top: 20px;
  width: 34px;
  height: 9px;
  border-radius: 999px;
  background: var(--gold);
}

.module-overview-grid {
  display: grid;
  gap: 14px;
  grid-template-columns: repeat(2, minmax(0, 1fr));
}

.landing-main-grid {
  grid-template-columns: repeat(5, minmax(0, 1fr));
}

.landing-personal-modules {
  margin-top: 14px;
}

.landing-personal-grid {
  grid-template-columns: repeat(2, minmax(220px, 1fr));
  max-width: 760px;
}

.landing-personal-grid .section-overview-card {
  min-height: 154px;
}

.landing-personal-grid .overview-card-icon {
  width: 52px;
  height: 52px;
}

.landing-personal-grid .overview-card-icon svg {
  width: 30px;
  height: 30px;
}

.landing-personal-grid .overview-card-copy small {
  display: none;
}

.overview-card {
  align-items: stretch;
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: 8px;
  color: var(--text);
  cursor: pointer;
  display: grid;
  gap: 14px;
  min-height: 230px;
  padding: 18px;
  text-align: left;
  transition: transform 140ms ease, border-color 140ms ease, box-shadow 140ms ease;
}

.overview-card:hover {
  border-color: var(--accent);
  box-shadow: var(--shadow);
  transform: translateY(-1px);
}

.overview-card.active {
  border-color: var(--accent);
  box-shadow: 0 0 0 2px var(--focus), var(--shadow);
}

.overview-card-group {
  cursor: default;
  gap: 0;
  overflow: hidden;
  padding: 0;
}

.overview-card-group:hover {
  border-color: var(--border);
  box-shadow: none;
  transform: none;
}

.overview-card-primary {
  background: transparent;
  border: 0;
  color: inherit;
  cursor: pointer;
  display: grid;
  font: inherit;
  gap: 14px;
  padding: 18px;
  text-align: left;
  width: 100%;
}

.overview-card-primary:hover,
.overview-card-primary.active,
.overview-subcard:hover,
.overview-subcard.active {
  background: var(--accent-soft);
}

.overview-card-primary.active,
.overview-subcard.active {
  box-shadow: inset 0 0 0 2px var(--focus);
}

.overview-card-top {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.overview-card-icon {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 44px;
  height: 44px;
  border-radius: 8px;
  background: var(--accent-soft);
  color: var(--accent-strong);
}

.overview-card-icon svg {
  width: 25px;
  height: 25px;
  fill: none;
  stroke: currentColor;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-width: 1.9;
}

.overview-card-badge {
  border: 1px solid var(--row-border);
  border-radius: 999px;
  color: var(--muted);
  font-size: 0.72rem;
  font-weight: 850;
  padding: 4px 8px;
}

.overview-card-copy {
  display: grid;
  gap: 6px;
}

.overview-card-copy strong {
  font-size: 1.18rem;
  line-height: 1.18;
}

.overview-card-copy span {
  color: var(--accent-strong);
  font-size: 0.86rem;
  font-weight: 900;
}

.overview-card-copy small {
  color: var(--muted);
  font-size: 0.82rem;
  font-weight: 700;
  line-height: 1.45;
  white-space: normal;
}

.overview-card-action {
  align-self: end;
  justify-self: start;
  border-radius: 6px;
  background: var(--accent);
  color: var(--surface);
  font-size: 0.82rem;
  font-weight: 900;
  padding: 9px 12px;
}

.overview-subcard-list {
  border-top: 1px solid var(--row-border);
  display: grid;
  padding: 10px;
}

.overview-subcard {
  align-items: center;
  background: var(--surface);
  border: 1px solid var(--row-border);
  border-radius: 8px;
  color: inherit;
  cursor: pointer;
  display: grid;
  font: inherit;
  gap: 10px;
  grid-template-columns: auto minmax(0, 1fr) auto;
  padding: 10px;
  text-align: left;
}

.overview-subcard .overview-card-icon {
  height: 34px;
  width: 34px;
}

.overview-subcard .overview-card-icon svg {
  height: 20px;
  width: 20px;
}

.overview-subcard-copy {
  display: grid;
  gap: 2px;
  min-width: 0;
}

.overview-subcard-copy strong {
  font-size: 0.92rem;
  line-height: 1.2;
}

.overview-subcard-copy small {
  color: var(--muted);
  font-size: 0.76rem;
  font-weight: 750;
  line-height: 1.35;
}

.overview-subcard-action {
  color: var(--accent-strong);
  font-size: 0.78rem;
  font-weight: 900;
}

.section-overview-card {
  min-height: 248px;
}

.module-topbar {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
  border-bottom: 1px solid var(--row-border);
  margin-bottom: 14px;
  padding-bottom: 12px;
}

.module-topbar > div:first-child {
  display: grid;
  gap: 2px;
}

.module-topbar strong {
  font-size: 0.92rem;
}

.module-topbar span {
  color: var(--muted);
  font-size: 0.78rem;
  font-weight: 800;
}

.module-topbar-actions {
  display: flex;
  flex-wrap: wrap;
  justify-content: flex-end;
  gap: 8px;
}

.workspace-grid {
  grid-template-columns: minmax(0, 1fr);
}

* {
  box-sizing: border-box;
}

[hidden] {
  display: none !important;
}

@media (max-width: 1240px) {
  .investment-grid {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 1080px) {
  .workspace-grid,
  .investment-control-grid {
    grid-template-columns: 1fr;
  }

  .toolbar,
  .app-header {
    align-items: stretch;
    flex-direction: column;
  }

  .position-filter-builder {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }
}

@media (max-width: 680px) {
  .app-header,
  .app-main {
    padding-left: 12px;
    padding-right: 12px;
  }

  .field-grid,
  .field-grid.wide,
  .investment-input-grid,
  .details-grid {
    grid-template-columns: 1fr;
  }

  .reserve-chart-popup {
    width: 100%;
    padding: 12px;
  }

  .result-header-actions {
    align-items: stretch;
    flex-direction: column;
  }

  .reserve-pie-layout,
  .reserve-pie-details {
    grid-template-columns: 1fr;
  }

  .range-field {
    grid-template-columns: 1fr;
  }

  .button-row {
    display: grid;
  }

  .position-filter-builder,
  .position-table-view-row {
    align-items: stretch;
    display: grid;
    grid-template-columns: 1fr;
  }

  .position-view-count {
    justify-self: start;
  }

  .investment-chart-header {
    padding: 16px 16px 0;
  }

  #investmentChart,
  #combinedInvestmentChart {
    height: 460px;
  }

  .investment-legend {
    justify-content: flex-start;
    gap: 12px;
    padding: 0 16px 16px;
  }

  .retirement-depot-funding {
    margin: 0 16px 16px;
  }

  .investment-statistics {
    margin: 0 16px 16px;
    grid-template-columns: 1fr;
  }
}

@media (max-width: 1220px) {
  .module-overview-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .landing-main-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .income-metric-grid {
    grid-template-columns: repeat(3, minmax(0, 1fr));
  }

  .income-tracker-grid {
    grid-template-columns: 1fr;
  }

  .combined-module-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .income-analysis-layout,
  .income-analysis-distribution-layout,
  .income-analysis-metrics {
    grid-template-columns: 1fr;
  }

  .income-analysis-distribution-detail {
    min-height: 240px;
  }
}

@media (max-width: 900px) {
  .landing-hero {
    min-height: 300px;
    padding: 28px;
  }

  .landing-hero-copy {
    min-height: 220px;
  }

  .landing-hero-graphic {
    right: 18px;
    width: 52%;
    min-width: 300px;
    opacity: 0.58;
  }

  .module-overview-grid {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .combined-module-grid {
    grid-template-columns: 1fr;
  }

  .account-year-table-metrics {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }

  .real-estate-slider-grid.two-columns {
    grid-template-columns: 1fr;
  }

  .wealth-bar-row {
    grid-template-columns: 56px 1fr;
  }

  .wealth-bar-value {
    grid-column: 1 / -1;
    justify-self: start;
  }

  .wealth-vertical-chart {
    grid-template-columns: 66px minmax(0, 1fr);
  }

  .wealth-plot {
    gap: 2px;
    padding-left: 4px;
    padding-right: 4px;
  }

  .wealth-column-button {
    gap: 4px;
    padding-left: 1px;
    padding-right: 1px;
  }

  .wealth-column-track {
    padding-left: 2px;
    padding-right: 2px;
  }

  .combined-wealth-summary {
    gap: 5px;
    padding-left: 2px;
    padding-right: 2px;
  }

  .combined-wealth-line-controls {
    justify-self: stretch;
    width: 100%;
  }

  .combined-wealth-card .wealth-plot {
    gap: 1px;
    grid-template-columns: repeat(var(--wealth-chart-count, 1), minmax(12px, 1fr));
    padding-left: 1px;
    padding-right: 1px;
  }

  .combined-wealth-ticks {
    gap: 1px;
    grid-template-columns: repeat(var(--wealth-chart-count, 1), minmax(12px, 1fr));
  }

  .statutory-pension-head,
  .statutory-pension-scenarios,
  .statutory-pension-overlay-legend,
  .statutory-pension-tax-summary {
    grid-template-columns: 1fr;
  }

  .income-chart-grid,
  .income-metric-grid {
    grid-template-columns: 1fr;
  }

  .income-tab-switch {
    grid-template-columns: repeat(2, minmax(0, 1fr));
  }
}

@media (max-width: 680px) {
  .landing-hero {
    min-height: 360px;
    padding: 84px 22px 22px;
  }

  .landing-hero-actions {
    left: 22px;
    right: 22px;
  }

  .landing-base-data-button {
    width: 100%;
  }

  .base-data-popup {
    left: 22px;
    right: 22px;
    top: 76px;
    width: auto;
    max-height: calc(100vh - 96px);
  }

  .landing-hero-copy h2 {
    font-size: 2.15rem;
  }

  .landing-hero-graphic {
    right: -64px;
    bottom: 4px;
    min-width: 330px;
    opacity: 0.42;
  }

  .module-overview-grid {
    grid-template-columns: 1fr;
  }

  .combined-single-selector.planning-account-cards {
    grid-template-columns: 1fr;
  }

  .combined-cash-account-selector.planning-account-cards {
    display: flex;
  }

  .overview-card {
    min-height: 0;
  }

  .module-topbar {
    align-items: stretch;
    flex-direction: column;
  }

  .module-topbar-actions,
  .module-topbar-actions .button {
    width: 100%;
  }

  .account-year-table-card {
    padding: 10px;
  }

  .account-year-table-actions,
  .account-year-table-actions .button {
    width: 100%;
  }

  .account-year-table-metrics {
    grid-template-columns: 1fr;
  }

  .income-tab-switch {
    grid-template-columns: 1fr;
  }

  .income-planning-metric-grid,
  .income-planning-time-block,
  .income-planning-time-charts,
  .income-planning-layout,
  .income-planning-scenario-grid,
  #incomePlanningWorkBlocks.income-planning-block-list,
  #incomePlanningManualBlocks.income-planning-block-list,
  .income-planning-habit-stamp-layout,
  .income-planning-weekly-head,
  .income-planning-week-toolbar,
  .income-planning-week-scenario,
  .income-planning-block-grid.work,
