import { describe, expect, it } from "vitest";

import { renderAccountYearTableOverview } from "../views/accountYearTables";
import { money } from "../lib/format";
import type { PlanningAccount, PlanningSettings, ReservePosition } from "../types";

const settings: PlanningSettings = {
  year: 2026,
  monthlyNetIncome: 0,
  interestRatePercent: 0,
  cashbackRatePercent: 0,
  endDate: "2088-12-31",
  emergencyFund: 0
};

describe("account year tables", () => {
  it("renders one read-only year table card for each account", () => {
    const html = renderAccountYearTableOverview({
      accounts: [account("konto-a", "Konto A", [income("income-a", 100)]), account("konto-b", "Konto B", [income("income-b", 50)])],
      settings,
      activeAccountId: "konto-a",
      showMaxNeeded: false
    });

    expect(count(html, "account-year-table-card")).toBe(2);
    expect(html).toContain("Konto A");
    expect(html).toContain("Konto B");
    expect(html).toContain("Aktives Konto fuer Grafik, Export und Bearbeitung");
    expect(html).toContain('data-action="select-planning-account-konto-b"');
  });

  it("keeps account summaries separated instead of merging all positions", () => {
    const html = renderAccountYearTableOverview({
      accounts: [
        account("konto-a", "Konto A", [income("income-a", 100), expense("expense-a", 25)]),
        account("konto-b", "Konto B", [income("income-b", 10), expense("expense-b", 5)])
      ],
      settings,
      activeAccountId: "konto-a",
      showMaxNeeded: false
    });

    expect(html).toContain(money(900));
    expect(html).toContain(money(60));
    expect(html).not.toContain(money(960));
  });

  it("uses the max-needed column toggle for every account table", () => {
    const accounts = [account("konto-a", "Konto A", [expense("expense-a", 25)]), account("konto-b", "Konto B", [expense("expense-b", 5)])];
    const withoutMaxNeeded = renderAccountYearTableOverview({
      accounts,
      settings,
      activeAccountId: "konto-a",
      showMaxNeeded: false
    });
    const withMaxNeeded = renderAccountYearTableOverview({
      accounts,
      settings,
      activeAccountId: "konto-a",
      showMaxNeeded: true
    });

    expect(withoutMaxNeeded).not.toContain("Max. Bedarf");
    expect(count(withMaxNeeded, "Max. Bedarf")).toBe(2);
  });
});

function account(id: string, name: string, yearlyRows: ReservePosition[]): PlanningAccount {
  return {
    id,
    name,
    type: "annual_table",
    yearlyRows
  };
}

function income(id: string, amount: number): ReservePosition {
  return position({
    id,
    name: id,
    flow: "income",
    type: "incomeMonthly",
    amount,
    payoutType: "monthly"
  });
}

function expense(id: string, amount: number): ReservePosition {
  return position({
    id,
    name: id,
    flow: "expense",
    type: "temporary",
    amount,
    payoutType: "monthly"
  });
}

function position(overrides: Partial<ReservePosition> & Pick<ReservePosition, "id" | "flow" | "type">): ReservePosition {
  return {
    active: true,
    visible: true,
    name: overrides.id,
    amount: 0,
    startMonth: 1,
    endMonth: 12,
    payoutYear: settings.year,
    payoutMonth: 12,
    payoutDay: 31,
    interestBearing: false,
    cashback: false,
    payoutType: "monthly",
    ...overrides
  };
}

function count(value: string, needle: string): number {
  return value.split(needle).length - 1;
}

/// <reference types="vite/client" />

import { readFileSync } from "node:fs";
import { afterEach, describe, expect, it, vi } from "vitest";

import mainSource from "../main.ts?raw";
import { defaultAppState } from "../data/defaults";
import { bindAppEvents } from "../app/events";
import { appSectionIdFromValue, createAppRouter, sectionFromLocationHash } from "../app/router";
import { createRenderScheduler, DEFAULT_RENDER_DEBOUNCE_MS } from "../app/renderScheduler";
import { createAppStore } from "../app/store/appStore";
import { featureModules } from "../features";
import type { AppState } from "../types";

const stylesIndexSource = readFileSync(new URL("../styles/index.css", import.meta.url), "utf8");

afterEach(() => {
  vi.unstubAllGlobals();
});

describe("app shell", () => {
  it("keeps main.ts as a bootstrap-only entry point", () => {
    expect(mainSource.split("\n").length).toBeLessThanOrEqual(50);
    expect(mainSource).toContain('import("./styles/index.css")');
    expect(mainSource).toContain('import("./app/bootstrap")');
    expect(mainSource).toContain('bootstrapApp("#app")');
    expect(mainSource).toContain("BlobFin bootstrap failed.");
    expect(mainSource).not.toContain("function bindEvents");
    expect(mainSource).not.toContain("function renderAll");
  });

  it("uses the split stylesheet entrypoint", () => {
    expect(stylesIndexSource).toContain('@import "./tokens.css" layer(tokens);');
    expect(stylesIndexSource).toContain('@import "./components/fields.css" layer(components);');
    expect(stylesIndexSource).toContain('@import "../features/income-stamp-planner/styles.css" layer(features);');
    expect(stylesIndexSource).toContain('@import "../features/self-employment/business-canvas/styles.css" layer(features);');
    expect(stylesIndexSource).not.toContain("legacy");
  });

  it("normalizes current route section ids and aliases", () => {
    expect(appSectionIdFromValue("income")).toBe("income");
    expect(appSectionIdFromValue("income_tracking")).toBe("income");
    expect(appSectionIdFromValue("year_table")).toBe("planning_scenarios");
    expect(appSectionIdFromValue("investment_overview")).toBe("planning_scenarios");
    expect(appSectionIdFromValue("unknown")).toBeNull();
    expect(sectionFromLocationHash("#income_charts")).toBe("income");
    expect(sectionFromLocationHash("#real_estate_financing")).toBe("real_estate_financing");
    expect(sectionFromLocationHash("")).toBeNull();
  });

  it("registers feature-sliced module entrypoints", () => {
    expect(featureModules.map((feature) => feature.id)).toEqual([
      "settings",
      "planning",
      "positions",
      "investment",
      "income-tracker",
      "income-planning",
      "income-stamp-planner",
      "self-employment",
      "business-canvas",
      "real-estate",
      "statutory-pension",
      "combined-wealth"
    ]);
    expect(featureModules.flatMap((feature) => feature.sections ?? [])).toContain("combined_wealth");
  });

  it("dispatches feature events before host handlers and keeps wheel non-passive", () => {
    vi.stubGlobal("window", createWindowStub());

    const calls: string[] = [];
    const listeners = new Map<string, { listener: EventListener; options?: AddEventListenerOptions }>();
    const root = {
      addEventListener: (type: string, listener: EventListener, options?: AddEventListenerOptions) => {
        listeners.set(type, { listener, options });
      },
      removeEventListener: () => undefined
    } as unknown as HTMLDivElement;
    const context = {
      root,
      store: createAppStore(defaultAppState()),
      router: createAppRouter(createRouterWindowStub()),
      scheduler: createRenderScheduler(() => undefined)
    };

    const dispose = bindAppEvents(
      context,
      [
        {
          id: "first",
          onClick: () => {
            calls.push("feature:first");
            return true;
          },
          onWindowKeyDown: () => {
            calls.push("window:first");
            return true;
          }
        },
        {
          id: "second",
          onClick: () => {
            calls.push("feature:second");
          }
        }
      ],
      {
        onClick: () => {
          calls.push("host");
        },
        onWindowKeyDown: () => {
          calls.push("window:host");
        }
      }
    );

    listeners.get("click")?.listener(new Event("click"));
    window.dispatchEvent(new Event("keydown"));

    expect(calls).toEqual(["feature:first", "window:first"]);
    expect(listeners.get("wheel")?.options).toMatchObject({ passive: false });
    dispose();
  });

  it("pushes and replaces section history through the app router", () => {
    const pushedUrls: string[] = [];
    const replacedUrls: string[] = [];
    const listeners = new Set<() => void>();
    const location = { hash: "", pathname: "/planner", search: "?profile=default" };
    const routerWindow = {
      location,
      history: {
        pushState: (_state: unknown, _title: string, url?: string | URL | null) => {
          pushedUrls.push(String(url));
          location.hash = String(url).replace(/^.*#/, "#");
        },
        replaceState: (_state: unknown, _title: string, url?: string | URL | null) => {
          replacedUrls.push(String(url));
          location.hash = String(url).replace(/^.*#/, "#");
        }
      },
      addEventListener: (_type: "popstate", listener: () => void) => {
        listeners.add(listener);
      },
      removeEventListener: (_type: "popstate", listener: () => void) => {
        listeners.delete(listener);
      }
    };
    const router = createAppRouter(routerWindow);

    router.pushSection("income");
    router.replaceSection("combined_wealth");

    expect(pushedUrls).toEqual(["/planner?profile=default#income"]);
    expect(replacedUrls).toEqual(["/planner?profile=default#combined_wealth"]);
    expect(router.currentSection()).toBe("combined_wealth");
  });

  it("debounces and flushes full renders", () => {
    let renderCount = 0;
    let pendingHandler: (() => void) | null = null;
    let clearedHandle: number | null = null;
    const scheduler = createRenderScheduler(
      () => {
        renderCount += 1;
      },
      DEFAULT_RENDER_DEBOUNCE_MS,
      {
        setTimeout: (handler, timeout) => {
          expect(timeout).toBe(DEFAULT_RENDER_DEBOUNCE_MS);
          pendingHandler = handler;
          return 1;
        },
        clearTimeout: (handle) => {
          clearedHandle = handle;
          pendingHandler = null;
        }
      }
    );
    const firePendingHandler = (): void => {
      const handler = pendingHandler;
      if (!handler) throw new Error("Expected a pending render handler.");
      handler();
    };

    scheduler.request();
    expect(scheduler.isPending()).toBe(true);
    scheduler.request();
    expect(clearedHandle).toBe(1);
    firePendingHandler();

    expect(renderCount).toBe(1);
    expect(scheduler.isPending()).toBe(false);
  });

  it("updates, notifies, and persists through AppStore", () => {
    const initialState = defaultAppState();
    const persistedStates: AppState[] = [];
    const store = createAppStore(initialState, (state) => persistedStates.push(state));
    const observedThemes: string[] = [];
    const unsubscribe = store.subscribe((state) => observedThemes.push(state.theme));

    store.replaceState({ ...initialState, theme: "dark" }, { persist: true });
    store.update((state) => ({ ...state, theme: "light" }), { notify: false });
    store.persistNow();
    unsubscribe();
    store.replaceState({ ...store.getState(), theme: "dark" });

    expect(store.getState().theme).toBe("dark");
    expect(observedThemes).toEqual(["dark"]);
    expect(persistedStates.map((state) => state.theme)).toEqual(["dark", "light"]);
  });
});

function createWindowStub(): Window {
  const target = new EventTarget();
  return {
    addEventListener: target.addEventListener.bind(target),
    removeEventListener: target.removeEventListener.bind(target),
    dispatchEvent: target.dispatchEvent.bind(target)
  } as Window;
}

function createRouterWindowStub() {
  return {
    location: { hash: "", pathname: "/", search: "" },
    history: {
      pushState: () => undefined,
      replaceState: () => undefined
    },
    addEventListener: () => undefined,
    removeEventListener: () => undefined
  };
}

/// <reference types="vite/client" />

import { describe, expect, it } from "vitest";

const sourceModules = import.meta.glob("../**/*.ts", {
  eager: true,
  import: "default",
  query: "?raw"
}) as Record<string, string>;
const tsxSourceModules = import.meta.glob("../**/*.tsx", {
  eager: true,
  import: "default",
  query: "?raw"
}) as Record<string, string>;
const cssSourceModules = import.meta.glob("../**/*.css", {
  eager: true,
  import: "default",
  query: "?raw"
}) as Record<string, string>;
const guardedSourceModules = {
  ...sourceModules,
  ...tsxSourceModules,
  ...cssSourceModules
};
const MAX_SOURCE_FILE_LINES = 1600;

const mainSource = sourceAt("../main.ts");
const appControllerSource = sourceAt("../app/appController.ts");
const controllerRuntimeSource = sourceAt("../app/controllerRuntime.ts");

const featureSources = Object.fromEntries(
  Object.entries(sourceModules).filter(([path]) => path.startsWith("../features/"))
);
const extractedFeatureSources = Object.fromEntries(
  Object.entries(featureSources).filter(([path]) => !path.startsWith("../features/runtime-host/"))
);

const runtimeHostHelperNames = [
  "activeInvestmentDepot",
  "activePlanningPositions",
  "activePlanningSettings",
  "depotInvestmentSettings",
  "persistCurrentState",
  "selectedInvestmentPlanningAccount",
  "setDetailLineHidden",
  "setInputValue",
  "setRangeLabel",
  "setSectionHidden",
  "setText",
  "syncStoreState"
] as const;

describe("architecture guards", () => {
  it("keeps TypeScript and CSS source files below the maximum line count", () => {
    const offenders = Object.entries(guardedSourceModules)
      .map(([path, source]) => ({ path, lines: lineCount(source) }))
      .filter(({ lines }) => lines > MAX_SOURCE_FILE_LINES)
      .map(({ path, lines }) => `${path}: ${lines} lines`);

    expect(offenders).toEqual([]);
  });

  it("keeps app entrypoints as thin facades", () => {
    expect(lineCount(mainSource)).toBeLessThanOrEqual(50);
    expect(lineCount(appControllerSource)).toBeLessThanOrEqual(30);
    expect(lineCount(controllerRuntimeSource)).toBeLessThanOrEqual(800);

    for (const [label, source] of [
      ["main.ts", mainSource],
      ["appController.ts", appControllerSource],
      ["controllerRuntime.ts", controllerRuntimeSource]
    ] as const) {
      expect(source, label).not.toContain("function bindEvents");
      expect(source, label).not.toContain("function renderAll");
      expect(source, label).not.toContain("data-action");
      expect(source, label).not.toContain('action === "business-canvas-');
      expect(source, label).not.toContain('action === "income-planning-');
      expect(source, label).not.toContain('action === "self-employment-');
      expect(source, label).not.toMatch(/\bfunction\s+render(?:Positions|Investment|RealEstate|Combined)/);
    }
  });

  it("does not reintroduce legacy adapter files", () => {
    const legacyPaths = Object.keys(sourceModules).filter((path) =>
      /(^|\/)legacy(\/|$)|legacyApp\.ts$/i.test(path)
    );

    expect(legacyPaths).toEqual([]);
  });

  it("keeps extracted features from importing app facades or the runtime host", () => {
    const offenders = Object.entries(extractedFeatureSources).flatMap(([path, source]) => {
      const imports = importsFrom(source);
      return imports
        .filter((importPath) =>
          /(?:^|\/)(?:appController|controllerRuntime)$/.test(importPath) ||
          importPath.includes("runtime-host")
        )
        .map((importPath) => `${path} imports ${importPath}`);
    });

    expect(offenders).toEqual([]);
  });

  it("keeps extracted features from calling runtime-host helpers as globals", () => {
    const offenders = Object.entries(extractedFeatureSources).flatMap(([path, source]) => {
      return runtimeHostHelperNames.flatMap((helperName) => {
        if (declaresFunction(source, helperName)) return [];
        return bareFunctionCallLines(source, helperName).map((line) => `${path}:${line} ${helperName}()`);
      });
    });

    expect(offenders).toEqual([]);
  });

  it("prevents DOM host variables from shadowing feature hosts", () => {
    const offenders = Object.entries(extractedFeatureSources).flatMap(([path, source]) => {
      return functionsInSource(source)
        .filter(({ body }) => /\b(?:const|let)\s+host\s*=\s*document\.querySelector/.test(body))
        .filter(({ body }) => /\bhost\.getState\s*\(/.test(body))
        .map(({ name, line }) => `${path}:${line} ${name}`);
    });

    expect(offenders).toEqual([]);
  });

  it("keeps feature barrel re-exports pointed at real bindings", () => {
    const offenders = Object.entries(featureSources).flatMap(([path, source]) => {
      if (!path.endsWith("/index.ts")) return [];
      return reExportsFrom(source).flatMap(({ names, target }) => {
        const targetPath = resolveRelativeTsPath(path, target);
        const targetSource = sourceModules[targetPath];
        if (!targetSource) return [`${path} re-exports from missing ${target}`];
        const exportedNames = exportedBindings(targetSource);
        return names
          .filter((name) => !exportedNames.has(name))
          .map((name) => `${path} re-exports missing ${name} from ${target}`);
      });
    });

    expect(offenders).toEqual([]);
  });
});

function lineCount(source: string): number {
  return source.split("\n").length;
}

function sourceAt(path: string): string {
  const source = sourceModules[path];
  if (!source) throw new Error(`Missing source module: ${path}`);
  return source;
}

function importsFrom(source: string): string[] {
  return Array.from(source.matchAll(/\bimport\s+(?:type\s+)?(?:[^"']+\s+from\s+)?["']([^"']+)["']/g)).map(
    (match) => match[1]
  );
}

function reExportsFrom(source: string): Array<{ names: string[]; target: string }> {
  return Array.from(source.matchAll(/\bexport\s*\{([^}]+)\}\s*from\s*["']([^"']+)["']/g)).map((match) => ({
    names: match[1]
      .split(",")
      .map((item) => item.trim())
      .filter((item) => item && !item.startsWith("type "))
      .map((item) => item.split(/\s+as\s+/)[0].trim()),
    target: match[2]
  }));
}

function resolveRelativeTsPath(fromPath: string, target: string): string {
  if (!target.startsWith(".")) return target;
  const baseParts = fromPath.split("/").slice(0, -1);
  for (const part of target.split("/")) {
    if (!part || part === ".") continue;
    if (part === "..") {
      baseParts.pop();
      continue;
    }
    baseParts.push(part);
  }
  const resolved = baseParts.join("/");
  return resolved.endsWith(".ts") ? resolved : `${resolved}.ts`;
}

function exportedBindings(source: string): Set<string> {
  const names = new Set<string>();
  for (const pattern of [
    /\bexport\s+(?:async\s+)?function\s+(\w+)/g,
    /\bexport\s+const\s+(\w+)/g,
    /\bexport\s+let\s+(\w+)/g,
    /\bexport\s+class\s+(\w+)/g,
    /\bexport\s+interface\s+(\w+)/g,
    /\bexport\s+type\s+(\w+)/g
  ]) {
    for (const match of source.matchAll(pattern)) names.add(match[1]);
  }
  for (const match of source.matchAll(/\bexport\s*\{([^}]+)\}/g)) {
    for (const item of match[1].split(",")) {
      const name = item.trim();
      if (name && !name.startsWith("type ")) names.add(name.split(/\s+as\s+/)[0].trim());
    }
  }
  return names;
}

function declaresFunction(source: string, name: string): boolean {
  return new RegExp(`(?:^|\\n)\\s*function\\s+${escapeRegExp(name)}\\s*\\(`).test(source);
}

function bareFunctionCallLines(source: string, name: string): number[] {
  const lines = source.split("\n");
  const callPattern = new RegExp(`(^|[^.\\w])${escapeRegExp(name)}\\s*\\(`);
  const declarationPattern = new RegExp(`\\b(function|const|let|var)\\s+${escapeRegExp(name)}\\b`);
  const methodSignaturePattern = new RegExp(`\\b${escapeRegExp(name)}\\s*\\([^)]*\\)\\s*:`);
  return lines.flatMap((line, index) => {
    if (!callPattern.test(line)) return [];
    if (declarationPattern.test(line)) return [];
    if (methodSignaturePattern.test(line)) return [];
    if (new RegExp(`\\b${escapeRegExp(name)}\\s*\\(.*\\)\\s*=>`).test(line)) return [];
    return [index + 1];
  });
}

function functionsInSource(source: string): Array<{ name: string; line: number; body: string }> {
  const functions: Array<{ name: string; line: number; body: string }> = [];
  const pattern = /\bfunction\s+(\w+)[^{]*\{/g;
  let match: RegExpExecArray | null;
  while ((match = pattern.exec(source))) {
    const start = match.index;
    const bodyEnd = matchingBraceEnd(source, pattern.lastIndex - 1);
    if (bodyEnd === -1) continue;
    functions.push({
      name: match[1],
      line: lineCount(source.slice(0, start)),
      body: source.slice(start, bodyEnd)
    });
    pattern.lastIndex = bodyEnd;
  }
  return functions;
}

function matchingBraceEnd(source: string, openBraceIndex: number): number {
  let depth = 0;
  for (let index = openBraceIndex; index < source.length; index += 1) {
    const char = source[index];
    if (char === "{") depth += 1;
    if (char === "}") {
      depth -= 1;
      if (depth === 0) return index + 1;
    }
  }
  return -1;
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

