  return {
    age,
    phase,
    grossBalance: netBalance,
    contribution: 0,
    costBasis: 0,
    allowance: 0,
    growth: 0,
    tax: 0,
    periodTax: 0,
    netBalance,
    realNetBalance: netBalance,
    normalDepot: netBalance
  };
}

function projection(points: AssetProjectionPoint[], monthlyPension = 0, retirementAge = 65): AssetProjection {
