      fixedInterestYears: 1,
      remainingDebtAfterFixedInterest: 99999,
      targetMonthlyBurden: 5000,
      maxMonthlyBurden: 1
    };

    const result = calculateRealEstateFinancing(state.settings.year, settings, schedule(repeated(1000, 36), [], [], 50000));

