    expect(state.ui.activeSection).toBe("home");
    expect(getVaultStatus().status).toBe("csvOnly");
  });

  it("keeps LocalStorage persistence available without a vault", () => {
    const storage = new MemoryStorage();
    const state = defaultAppState();
