            <th>Netto uebrig</th>
            ${maxNeededHead}
            <th class="result-permanent-col"><span class="split-header">Dauerhafter<span>Bestand</span></span></th>
            <th class="result-interest-col"><span class="split-header">ca.<span>Monatszins</span></span></th>
            <th>Cashback</th>
          </tr>
        </thead>
        <tbody>
          ${summary.rows
            .map(
              (row) => `
